// Domain Types

export interface ShortsData {
  id: string;
  title: string;
  hashtags: string[];
  view_count: number;
  region: string;
  view_growth_rate: number;
}

export interface TrendSignals {
  action_verb_frequency: Record<string, number>;
  subject_type_frequency: Record<string, number>;
  object_type_frequency: Record<string, number>;
  structure_type_frequency: Record<string, number>;
  algorithm_signal_frequency: Record<string, number>;
}

export interface CandidateTheme {
  id: string;
  subject_type: string;
  action_verb: string;
  object_type: string;
  structure_type: string;
  algorithm_signals: string[];
  rationale?: string;
  // Weight Engine Output fields
  total_score?: number;
  selected?: boolean;
  scoring_breakdown?: {
    virality: number;
    feasibility: number;
    trend_alignment: number;
  };
}

export interface ChannelState {
  niche: string;
  avg_views: number;
  target_audience: string;
}

export interface PromptOutput {
  candidate_id: string;
  prompt: string;
  title_template: string;
  description_template: string;
  candidate_reference: CandidateTheme;
}

// Module Interfaces
export interface IModule<Input, Output> {
  name: string;
  description: string;
  execute(input: Input): Promise<Output>;
}

export interface TestResult {
  moduleName: string;
  passed: boolean;
  logs: string[];
}

import { GoogleGenAI, Type } from "@google/genai";

// Ensure API Key is present
const API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

const modelId = "gemini-2.5-flash";

export const generateJSON = async <T>(
  prompt: string,
  systemInstruction: string,
  responseSchema?: any
): Promise<T> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.2, // Low temperature for deterministic structural output
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No text returned from Gemini.");
    }

    return JSON.parse(text) as T;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import { ShortsData, TrendSignals, IModule } from '../types';
import { generateJSON } from '../services/geminiService';
import { SYSTEM_INSTRUCTIONS } from '../constants';
import { Type } from '@google/genai';

export class TrendSignalExtractor implements IModule<ShortsData[], TrendSignals> {
  name = "Trend Signal Extractor";
  description = "Analyzes raw Shorts data to extract frequency maps of verbs, subjects, and structures.";

  async execute(input: ShortsData[]): Promise<TrendSignals> {
    const prompt = `
      Analyze the following YouTube Shorts dataset:
      ${JSON.stringify(input, null, 2)}

      Return a statistical summary of the trends found.
    `;

    // Define schema for strict output
    const schema = {
      type: Type.OBJECT,
      properties: {
        action_verb_frequency: { type: Type.OBJECT, additionalProperties: { type: Type.NUMBER } },
        subject_type_frequency: { type: Type.OBJECT, additionalProperties: { type: Type.NUMBER } },
        object_type_frequency: { type: Type.OBJECT, additionalProperties: { type: Type.NUMBER } },
        structure_type_frequency: { type: Type.OBJECT, additionalProperties: { type: Type.NUMBER } },
        algorithm_signal_frequency: { type: Type.OBJECT, additionalProperties: { type: Type.NUMBER } },
      },
      required: [
        "action_verb_frequency",
        "subject_type_frequency",
        "object_type_frequency",
        "structure_type_frequency",
        "algorithm_signal_frequency"
      ],
    };

    return await generateJSON<TrendSignals>(prompt, SYSTEM_INSTRUCTIONS.TREND_EXTRACTOR, schema);
  }
}

import { TrendSignals, CandidateTheme, IModule } from '../types';
import { generateJSON } from '../services/geminiService';
import { SYSTEM_INSTRUCTIONS } from '../constants';
import { Type } from '@google/genai';

export class CandidateThemeGenerator implements IModule<TrendSignals, CandidateTheme[]> {
  name = "Candidate Theme Generator";
  description = "Generates video candidates based on extracted trend signals.";

  async execute(input: TrendSignals): Promise<CandidateTheme[]> {
    const prompt = `
      Using these Trend Signals:
      ${JSON.stringify(input, null, 2)}

      Generate 3 potential viral Shorts concepts.
    `;

    const schema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          subject_type: { type: Type.STRING },
          action_verb: { type: Type.STRING },
          object_type: { type: Type.STRING },
          structure_type: { type: Type.STRING },
          algorithm_signals: { type: Type.ARRAY, items: { type: Type.STRING } },
          rationale: { type: Type.STRING }
        },
        required: ["id", "subject_type", "action_verb", "object_type", "structure_type", "algorithm_signals"]
      }
    };

    return await generateJSON<CandidateTheme[]>(prompt, SYSTEM_INSTRUCTIONS.CANDIDATE_GENERATOR, schema);
  }
}

import { CandidateTheme, ChannelState, IModule } from '../types';
import { generateJSON } from '../services/geminiService';
import { SYSTEM_INSTRUCTIONS } from '../constants';
import { Type } from '@google/genai';

interface WeightEngineInput {
  candidates: CandidateTheme[];
  channelState: ChannelState;
}

export class CandidateWeightEngine implements IModule<WeightEngineInput, CandidateTheme[]> {
  name = "Candidate Weight Engine";
  description = "Scores candidates and selects the best one based on channel fit and virality.";

  async execute(input: WeightEngineInput): Promise<CandidateTheme[]> {
    const prompt = `
      Channel State: ${JSON.stringify(input.channelState, null, 2)}

      Candidates to Score:
      ${JSON.stringify(input.candidates, null, 2)}

      Score them and mark exactly one as 'selected': true.
    `;

    const schema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          subject_type: { type: Type.STRING },
          action_verb: { type: Type.STRING },
          object_type: { type: Type.STRING },
          structure_type: { type: Type.STRING },
          algorithm_signals: { type: Type.ARRAY, items: { type: Type.STRING } },
          rationale: { type: Type.STRING },
          total_score: { type: Type.NUMBER },
          selected: { type: Type.BOOLEAN },
          scoring_breakdown: {
             type: Type.OBJECT,
             properties: {
                virality: {type: Type.NUMBER},
                feasibility: {type: Type.NUMBER},
                trend_alignment: {type: Type.NUMBER}
             }
          }
        },
        required: ["id", "subject_type", "total_score", "selected"]
      }
    };

    return await generateJSON<CandidateTheme[]>(prompt, SYSTEM_INSTRUCTIONS.WEIGHT_ENGINE, schema);
  }
}

import { CandidateTheme, PromptOutput, IModule } from '../types';
import { generateJSON } from '../services/geminiService';
import { SYSTEM_INSTRUCTIONS } from '../constants';
import { Type } from '@google/genai';

export class PromptComposer implements IModule<CandidateTheme, PromptOutput> {
  name = "Prompt Composer";
  description = "Generates the final video production prompt, title, and description.";

  async execute(input: CandidateTheme): Promise<PromptOutput> {
    if (!input.selected) {
      throw new Error("Input candidate must be selected.");
    }

    const prompt = `
      Create production assets for this selected candidate:
      ${JSON.stringify(input, null, 2)}
    `;

    const schema = {
      type: Type.OBJECT,
      properties: {
        candidate_id: { type: Type.STRING },
        prompt: { type: Type.STRING },
        title_template: { type: Type.STRING },
        description_template: { type: Type.STRING },
        candidate_reference: {
            type: Type.OBJECT,
            properties: {
                id: {type: Type.STRING},
                subject_type: {type: Type.STRING},
                action_verb: {type: Type.STRING}
            }
        }
      },
      required: ["candidate_id", "prompt", "title_template", "description_template"]
    };

    return await generateJSON<PromptOutput>(prompt, SYSTEM_INSTRUCTIONS.PROMPT_COMPOSER, schema);
  }
}

import { TrendSignalExtractor } from '../modules/TrendSignalExtractor';
import { MOCK_SHORTS_DATA } from '../constants';
import { TestResult } from '../types';

export const runTrendExtractorTests = async (): Promise<TestResult> => {
  const logs: string[] = [];
  const module = new TrendSignalExtractor();

  logs.push("Running TrendSignalExtractor tests...");

  try {
    const result = await module.execute(MOCK_SHORTS_DATA.slice(0, 2));

    // Assertion 1: Check structure
    if (!result.action_verb_frequency) throw new Error("Missing action_verb_frequency");
    if (!result.subject_type_frequency) throw new Error("Missing subject_type_frequency");

    logs.push("✅ Output Schema Validated");
    logs.push(`Sample output key count: ${Object.keys(result.action_verb_frequency).length}`);

    return { moduleName: "TrendSignalExtractor", passed: true, logs };
  } catch (e: any) {
    logs.push(`❌ Test Failed: ${e.message}`);
    return { moduleName: "TrendSignalExtractor", passed: false, logs };
  }
};

