                title="Prompt Composer"
                description="Generates final prompt, title template, and description for the winner."
                status={s4Status}
                canExecute={!!scoredCandidates}
                onExecute={handleExecuteComposer}
                onRunTest={runTest4}
                testResult={t4Result}
                data={promptOutput}
              />
            </div>
          </div>
        </div>

      </div>

