import { GoogleGenAI, Type } from "@google/genai";

// Ensure API Key is present
const API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

const textModelId = "gemini-2.5-flash";
const videoModelId = "veo-3.1-fast-generate-preview";

export const generateJSON = async <T>(
  prompt: string,
  systemInstruction: string,
  responseSchema?: any
): Promise<T> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }

  try {
    const response = await ai.models.generateContent({
      model: textModelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.2, // Low temperature for deterministic structural output
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No text returned from Gemini.");
    }

    return JSON.parse(text) as T;
  } catch (error) {
    console.error("Gemini API Error (Text):", error);
    throw error;
  }
};

export const generateVideo = async (prompt: string): Promise<string> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }

  try {
    console.log("Starting Veo generation...");
    let operation = await ai.models.generateVideos({
      model: videoModelId,
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '9:16' // Shorts format
      }
    });

    console.log("Video operation started, polling...", operation);

    // Polling loop
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000)); // Poll every 5s
      operation = await ai.operations.getVideosOperation({operation: operation});
      console.log("Polling status:", operation.metadata?.state);
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("Video generation completed but no URI returned.");
    }

    // Fetch the raw MP4 bytes
    const response = await fetch(`${downloadLink}&key=${API_KEY}`);
    if (!response.ok) {
      throw new Error(`Failed to download video bytes: ${response.statusText}`);
    }

    const blob = await response.blob();
    return URL.createObjectURL(blob);

  } catch (error) {
    console.error("Gemini API Error (Video):", error);
    throw error;
  }
};

import { PromptOutput, VideoAsset, IModule } from '../types';
import { generateVideo } from '../services/geminiService';

/**
 * Phase 5: Video Generator
 * 
 * Goal: Generate a real video using the Veo model based on the optimized prompt.
 * Input: PromptOutput
 * Output: VideoAsset (Blob URL)
 */
export class VideoGenerator implements IModule<PromptOutput, VideoAsset> {
  name = "Video Generator";
  description = "Generates actual MP4 video using Veo (AI Video Model).";

  async execute(input: PromptOutput): Promise<VideoAsset> {
    if (!input.prompt) {
      throw new Error("Input prompt cannot be empty.");
    }
    if (!input.candidate_id) {
      throw new Error("Input candidate_id is missing.");
    }

    try {
      // Call the service to hit Veo API
      const videoUrl = await generateVideo(input.prompt);

      return {
        candidate_id: input.candidate_id,
        video_url: videoUrl,
        mime_type: "video/mp4",
        status: "generated",
        generated_at: new Date().toISOString()
      };

    } catch (error) {
      console.error("VideoGenerator Execution Failed:", error);
      // For demo purposes, we might want to propagate the error, 
      // but in a real pipeline, we might return a 'failed' status object.
      // Here we throw to let the UI handle the error state.
      throw error;
    }
  }
}

