export const ModuleCard: React.FC<ModuleCardProps> = ({
  title,
  description,
  status,
  onRunTest,
  onExecute,
  canExecute,
  data,
  testResult,
  stepNumber,
  children
}) => {
  const [testStatus, setTestStatus] = useState<'idle' | 'running' | 'done'>('idle');
