import { GoogleGenAI } from "@google/genai";

// Ensure API Key is present
// Note: In Next.js/Vercel, process.env.API_KEY is available on the server side.
const API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

const textModelId = "gemini-2.5-flash";
const videoModelId = "veo-3.1-fast-generate-preview";

export const generateJSON = async <T>(
  prompt: string,
  systemInstruction: string,
  responseSchema?: any
): Promise<T> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please check server configuration.");
  }

  try {
    const response = await ai.models.generateContent({
      model: textModelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.2, 
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No text returned from Gemini.");
    }

    return JSON.parse(text) as T;
  } catch (error) {
    console.error("Gemini API Error (Text):", error);
    throw error;
  }
};

export const generateVideo = async (prompt: string): Promise<string> => {
  if (!API_KEY) {
    throw new Error("API Key is missing.");
  }

  try {
    console.log("Starting Veo generation (Server-Side)...");
    let operation = await ai.models.generateVideos({
      model: videoModelId,
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '9:16'
      }
    });

    // Polling loop
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.operations.getVideosOperation({operation: operation});
      console.log("Polling status:", operation.metadata?.state);
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("Video generation completed but no URI returned.");
    }

    // Fetch the raw MP4 bytes using the API Key
    const response = await fetch(`${downloadLink}&key=${API_KEY}`);
    if (!response.ok) {
      throw new Error(`Failed to download video bytes: ${response.statusText}`);
    }

    // Convert to Base64 Data URI for frontend consumption
    const arrayBuffer = await response.arrayBuffer();

    // Convert ArrayBuffer to Base64
    // Safe implementation for environments where Buffer might not be globally typed (e.g. Frontend TS config)
    let base64 = '';
    if (typeof globalThis !== 'undefined' && (globalThis as any).Buffer) {
        base64 = (globalThis as any).Buffer.from(arrayBuffer).toString('base64');
    } else {
        // Fallback using standard Web APIs
        const bytes = new Uint8Array(arrayBuffer);
        let binary = '';
        const len = bytes.byteLength;
        for (let i = 0; i < len; i++) {
            binary += String.fromCharCode(bytes[i]);
        }
        base64 = btoa(binary);
    }

    return `data:video/mp4;base64,${base64}`;

  } catch (error) {
    console.error("Gemini API Error (Video):", error);
    throw error;
  }
};

// Domain Types

export interface ShortsData {
  id: string;
  title: string;
  hashtags: string[];
  view_count: number;
  region: string;
  view_growth_rate: number;
}

export interface TrendSignals {
  action_verb_frequency: Record<string, number>;
  subject_type_frequency: Record<string, number>;
  object_type_frequency: Record<string, number>;
  structure_type_frequency: Record<string, number>;
  algorithm_signal_frequency: Record<string, number>;
}

export interface CandidateTheme {
  id: string;
  subject_type: string;
  action_verb: string;
  object_type: string;
  structure_type: string;
  algorithm_signals: string[];
  rationale?: string;
  // Weight Engine Output fields
  total_score?: number;
  selected?: boolean;
  scoring_breakdown?: {
    virality: number;
    feasibility: number;
    trend_alignment: number;
  };
}

export interface ChannelState {
  niche: string;
  avg_views: number;
  target_audience: string;
}

export interface PromptOutput {
  candidate_id: string;
  prompt: string;
  title_template: string;
  description_template: string;
  candidate_reference: CandidateTheme;
}

export interface VideoAsset {
  candidate_id: string;
  video_url: string; // Blob URL (Frontend) or Data URI (Backend)
  mime_type: string;
  status: 'generated' | 'failed';
  generated_at: string;
}

export interface ScheduleConfig {
  publish_at?: string; // ISO Date string for scheduled release
  privacy_status: 'private' | 'public' | 'unlisted';
}

export interface AuthCredentials {
  access_token: string;
  refresh_token?: string;
  scope?: string;
  token_type?: string;
  expiry_date?: number;
}

export interface UploaderInput {
  video_asset: VideoAsset;
  metadata: PromptOutput;
  schedule: ScheduleConfig;
  authCredentials?: AuthCredentials; // Added for Real YouTube API
}

export interface UploadResult {
  platform: 'youtube';
  video_id: string;
  platform_url: string;
  status: 'uploaded' | 'scheduled' | 'failed';
  scheduled_for?: string;
  uploaded_at: string;
}

// Module Interfaces
export interface IModule<Input, Output> {
  name: string;
  description: string;
  execute(input: Input): Promise<Output>;
}

export interface TestResult {
  moduleName: string;
  passed: boolean;
  logs: string[];
}

import { google } from 'googleapis';

const CLIENT_ID = process.env.GOOGLE_CLIENT_ID;
const CLIENT_SECRET = process.env.GOOGLE_CLIENT_SECRET;
const REDIRECT_URI = process.env.GOOGLE_REDIRECT_URI || 'http://localhost:3000/';

const oauth2Client = new google.auth.OAuth2(
  CLIENT_ID,
  CLIENT_SECRET,
  REDIRECT_URI
);

export default async function handler(req: any, res: any) {
  // Check for GET request to generate URL
  if (req.method === 'GET') {
    const { action, code } = req.query;

    if (action === 'url') {
      const scopes = [
        'https://www.googleapis.com/auth/youtube.upload',
        'https://www.googleapis.com/auth/youtube.readonly'
      ];

      const url = oauth2Client.generateAuthUrl({
        access_type: 'offline',
        scope: scopes,
        prompt: 'consent' // Force refresh token
      });

      return res.status(200).json({ url });
    }
  }

  // Check for POST request to exchange code
  if (req.method === 'POST') {
    const { code } = req.body;
    if (!code) {
      return res.status(400).json({ error: 'Missing auth code' });
    }

    try {
      const { tokens } = await oauth2Client.getToken(code);
      return res.status(200).json({ tokens });
    } catch (error: any) {
      console.error('Error exchanging token:', error);
      return res.status(500).json({ error: error.message });
    }
  }

  return res.status(400).json({ error: 'Invalid request' });
}

import { UploaderInput, UploadResult, IModule } from '../types';
import { google } from 'googleapis';
import { Readable } from 'stream';

/**
 * Phase 6: Uploader & Scheduler (Real Implementation)
 * 
 * Goal: Upload video to YouTube using OAuth2 credentials.
 */
export class UploaderScheduler implements IModule<UploaderInput, UploadResult> {
  name = "Uploader & Scheduler";
  description = "Uploads video to YouTube via API and configures release schedule.";

  async execute(input: UploaderInput): Promise<UploadResult> {
    // 1. Validation
    if (!input.video_asset || input.video_asset.status !== 'generated') {
      throw new Error("Invalid video asset.");
    }
    if (!input.metadata || !input.metadata.title_template) {
      throw new Error("Missing video metadata.");
    }

    // 2. Check for Credentials (Real Mode) vs Simulation
    if (input.authCredentials && process.env.GOOGLE_CLIENT_ID) {
      return this.uploadReal(input);
    } else {
      console.warn("[Uploader] Missing OAuth Credentials. Falling back to Simulation.");
      return this.uploadSimulated(input);
    }
  }

  private async uploadReal(input: UploaderInput): Promise<UploadResult> {
    console.log(`[Uploader] Starting REAL upload to YouTube...`);

    const oauth2Client = new google.auth.OAuth2(
      process.env.GOOGLE_CLIENT_ID,
      process.env.GOOGLE_CLIENT_SECRET,
      process.env.GOOGLE_REDIRECT_URI
    );

    oauth2Client.setCredentials(input.authCredentials!);

    const service = google.youtube({ version: 'v3', auth: oauth2Client });

    // Convert Base64 Data URI to Stream
    const videoStream = this.base64ToStream(input.video_asset.video_url);

    try {
      const response = await service.videos.insert({
        part: ['snippet', 'status'],
        requestBody: {
          snippet: {
            title: input.metadata.title_template,
            description: input.metadata.description_template + "\n\n#Shorts",
            tags: ["Shorts", "AI", "Automated"],
            categoryId: '28' // Science & Technology
          },
          status: {
            privacyStatus: input.schedule.privacy_status,
            publishAt: input.schedule.publish_at // Only works if privacyStatus is private/scheduled logic
          }
        },
        media: {
          body: videoStream,
          mimeType: 'video/mp4'
        }
      });

      console.log(`[Uploader] Upload Success! ID: ${response.data.id}`);

      return {
        platform: 'youtube',
        video_id: response.data.id || 'unknown',
        platform_url: `https://youtube.com/shorts/${response.data.id}`,
        status: input.schedule.publish_at ? 'scheduled' : 'uploaded',
        scheduled_for: input.schedule.publish_at,
        uploaded_at: new Date().toISOString()
      };

    } catch (error: any) {
      console.error("[Uploader] API Error:", error);
      throw new Error(`YouTube API Upload Failed: ${error.message}`);
    }
  }

  private async uploadSimulated(input: UploaderInput): Promise<UploadResult> {
    console.log(`[Uploader] Starting SIMULATED upload...`);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const mockId = "dQw4w9WgXcQ"; 
    return {
      platform: 'youtube',
      video_id: mockId,
      platform_url: `https://youtube.com/shorts/${mockId}`,
      status: input.schedule.publish_at ? 'scheduled' : 'uploaded',
      scheduled_for: input.schedule.publish_at,
      uploaded_at: new Date().toISOString()
    };
  }

  private base64ToStream(dataUri: string): Readable {
    // Expected format: "data:video/mp4;base64,....."
    const base64Data = dataUri.split(';base64,').pop();
    if (!base64Data) throw new Error("Invalid Base64 URI");

    const buffer = Buffer.from(base64Data, 'base64');
    const stream = new Readable();
    stream.push(buffer);
    stream.push(null);
    return stream;
  }
}

import { GoogleGenAI } from "@google/genai";
import { TrendSignalExtractor } from '../modules/TrendSignalExtractor';
import { CandidateThemeGenerator } from '../modules/CandidateThemeGenerator';
import { CandidateWeightEngine } from '../modules/CandidateWeightEngine';
import { PromptComposer } from '../modules/PromptComposer';
import { VideoGenerator } from '../modules/VideoGenerator';
import { UploaderScheduler } from '../modules/UploaderScheduler';

// Backend logic to handle requests
export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const { step, input } = req.body;

  if (!process.env.API_KEY) {
    return res.status(500).json({ error: 'Server configuration error: API_KEY is missing.' });
  }

  try {
    let result;

    switch (step) {
      case 'trend':
        const extractor = new TrendSignalExtractor();
        result = await extractor.execute(input);
        break;

      case 'candidate':
        const generator = new CandidateThemeGenerator();
        result = await generator.execute(input);
        break;

      case 'weight':
        const weighter = new CandidateWeightEngine();
        result = await weighter.execute(input);
        break;

      case 'prompt':
        const composer = new PromptComposer();
        result = await composer.execute(input);
        break;

      case 'video':
        const videoGen = new VideoGenerator();
        result = await videoGen.execute(input);
        break;

      case 'upload':
        const uploader = new UploaderScheduler();
        // input should now contain { video_asset, metadata, schedule, authCredentials }
        if (input.authCredentials) {
            console.log("Server: Using User-Provided OAuth Credentials for Upload.");
        } else {
            console.log("Server: No OAuth Credentials provided, defaulting to simulation.");
        }
        result = await uploader.execute(input);
        break;

      default:
        return res.status(400).json({ error: 'Invalid step specified' });
    }

    return res.status(200).json(result);

  } catch (error: any) {
    console.error(`API Error in step ${step}:`, error);
    return res.status(500).json({ error: error.message || 'Internal Server Error' });
  }
}

import React, { useState, useEffect } from 'react';
import { ModuleCard } from './components/ModuleCard';
import { DataInputForm } from './components/DataInputForm';

import { MOCK_SHORTS_DATA, MOCK_CHANNEL_STATE } from './constants';
import { 
  TrendSignals, CandidateTheme, PromptOutput, VideoAsset, 
  UploadResult, TestResult, ShortsData, ChannelState, AuthCredentials 
} from './types';

const App: React.FC = () => {
  // --- Input Data State ---
  const [inputShorts, setInputShorts] = useState<ShortsData[]>(MOCK_SHORTS_DATA);
  const [inputChannel, setInputChannel] = useState<ChannelState>(MOCK_CHANNEL_STATE);

  // --- Auth State ---
  const [youtubeTokens, setYoutubeTokens] = useState<AuthCredentials | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(false);

  // --- Pipeline State ---
  const [pipelineState, setPipelineState] = useState({
    trendSignals: null as TrendSignals | null,
    candidates: null as CandidateTheme[] | null,
    scoredCandidates: null as CandidateTheme[] | null,
    promptOutput: null as PromptOutput | null,
    videoAsset: null as VideoAsset | null,
    uploadResult: null as UploadResult | null,
  });

  const [statuses, setStatuses] = useState({
    s1: 'idle' as const,
    s2: 'idle' as const,
    s3: 'idle' as const,
    s4: 'idle' as const,
    s5: 'idle' as const,
    s6: 'idle' as const,
  });

  const [testResults, setTestResults] = useState({
    t1: null as TestResult | null,
    t2: null as TestResult | null,
    t3: null as TestResult | null,
    t4: null as TestResult | null,
    t5: null as TestResult | null,
    t6: null as TestResult | null,
  });

  const [globalProgress, setGlobalProgress] = useState(0);
  const [isAutoRunning, setIsAutoRunning] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // --- OAuth Code Handling ---
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const code = params.get('code');

    if (code) {
      // Exchange code for tokens
      const exchangeCode = async () => {
        setIsAuthLoading(true);
        try {
          const res = await fetch('/api/auth', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ code })
          });
          const data = await res.json();
          if (data.tokens) {
            setYoutubeTokens(data.tokens);
            // Clean URL
            window.history.replaceState({}, document.title, window.location.pathname);
          }
        } catch (e) {
          console.error("Auth Exchange Error", e);
          setErrorMsg("YouTube 授權失敗");
        } finally {
          setIsAuthLoading(false);
        }
      };
      exchangeCode();
    }
  }, []);

  const handleConnectYouTube = async () => {
    try {
      const res = await fetch('/api/auth?action=url');
      const data = await res.json();
      if (data.url) {
        window.location.href = data.url;
      }
    } catch (e) {
      setErrorMsg("無法獲取授權連結");
    }
  };

  // --- API Helper ---
  const callApi = async (step: string, input: any) => {
    const response = await fetch('/api/pipeline', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ step, input }),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `Server Error: ${response.status}`);
    }

    return await response.json();
  };

  const updateStatus = (step: keyof typeof statuses, status: typeof statuses['s1']) => {
    setStatuses(prev => ({ ...prev, [step]: status }));
  };

  // --- Execution Handlers (Calling Backend) ---

  const step1_Extract = async () => {
    updateStatus('s1', 'loading'); setErrorMsg(null);
    try {
      const res = await callApi('trend', inputShorts);
      setPipelineState(prev => ({ ...prev, trendSignals: res }));
      updateStatus('s1', 'success');
      return res;
    } catch (e: any) { setErrorMsg(e.message); updateStatus('s1', 'error'); throw e; }
  };

  const step2_Generate = async (input = pipelineState.trendSignals) => {
    if (!input) throw new Error("缺少趨勢訊號資料");
    updateStatus('s2', 'loading'); setErrorMsg(null);
    try {
      const res = await callApi('candidate', input);
      setPipelineState(prev => ({ ...prev, candidates: res }));
      updateStatus('s2', 'success');
      return res;
    } catch (e: any) { setErrorMsg(e.message); updateStatus('s2', 'error'); throw e; }
  };

  const step3_Weight = async (input = pipelineState.candidates) => {
    if (!input) throw new Error("缺少候選題材資料");
    updateStatus('s3', 'loading'); setErrorMsg(null);
    try {
      const res = await callApi('weight', { candidates: input, channelState: inputChannel });
      setPipelineState(prev => ({ ...prev, scoredCandidates: res }));
      updateStatus('s3', 'success');
      return res;
    } catch (e: any) { setErrorMsg(e.message); updateStatus('s3', 'error'); throw e; }
  };

  const step4_Compose = async (input = pipelineState.scoredCandidates) => {
    if (!input) throw new Error("缺少已評分題材資料");
    updateStatus('s4', 'loading'); setErrorMsg(null);
    try {
      const selected = input.find(c => c.selected);
      if (!selected) throw new Error("權重引擎未選出優勝題材");
      const res = await callApi('prompt', selected);
      setPipelineState(prev => ({ ...prev, promptOutput: res }));
      updateStatus('s4', 'success');
      return res;
    } catch (e: any) { setErrorMsg(e.message); updateStatus('s4', 'error'); throw e; }
  };

  const step5_Video = async (input = pipelineState.promptOutput) => {
    if (!input) throw new Error("缺少 Prompt 資料");
    updateStatus('s5', 'loading'); setErrorMsg(null);
    try {
      const res = await callApi('video', input);
      setPipelineState(prev => ({ ...prev, videoAsset: res }));
      updateStatus('s5', 'success');
      return res;
    } catch (e: any) { setErrorMsg(e.message); updateStatus('s5', 'error'); throw e; }
  };

  const step6_Upload = async (videoAsset = pipelineState.videoAsset, metadata = pipelineState.promptOutput) => {
    if (!videoAsset || !metadata) throw new Error("缺少影片或 Metadata 資料");
    updateStatus('s6', 'loading'); setErrorMsg(null);

    // Inject Credentials if available
    const authToUse = youtubeTokens ? youtubeTokens : undefined;

    try {
      const tomorrow = new Date(); tomorrow.setDate(tomorrow.getDate() + 1);
      const res = await callApi('upload', {
        video_asset: videoAsset, 
        metadata: metadata,
        schedule: { privacy_status: 'public', publish_at: tomorrow.toISOString() },
        authCredentials: authToUse
      });
      setPipelineState(prev => ({ ...prev, uploadResult: res }));
      updateStatus('s6', 'success');
      return res;
    } catch (e: any) { setErrorMsg(e.message); updateStatus('s6', 'error'); throw e; }
  };

  // --- Automation Orchestrator ---
  const runFullAutomation = async () => {
    if (isAutoRunning) return;
    setIsAutoRunning(true);
    setGlobalProgress(5);
    setErrorMsg(null);
    setStatuses({ s1: 'idle', s2: 'idle', s3: 'idle', s4: 'idle', s5: 'idle', s6: 'idle' });

    try {
      const s1 = await step1_Extract(); setGlobalProgress(20);
      const s2 = await step2_Generate(s1); setGlobalProgress(35);
      const s3 = await step3_Weight(s2); setGlobalProgress(50);
      const s4 = await step4_Compose(s3); setGlobalProgress(65);
      const s5 = await step5_Video(s4); setGlobalProgress(85);
      await step6_Upload(s5, s4); setGlobalProgress(100);
