                 </h4>
                 {pipelineState.uploadResult.status !== 'failed' && (
                    <a href={pipelineState.uploadResult.platform_url} target="_blank" className="text-blue-400 underline block mt-2">
                        {pipelineState.uploadResult.platform_url}
                    </a>
                 )}
               </div>
             )}
           </ModuleCard>

        </div>
