const MOCK_INPUT: UploaderInput = {
  video_asset: {
    candidate_id: "test_1",
    video_url: "blob:xxx",
    mime_type: "video/mp4",
    status: "generated",
    generated_at: new Date().toISOString()
  },
  metadata: {
