import { TrendSearcher } from '../modules/TrendSearcher';
import { TrendSignalExtractor } from '../modules/TrendSignalExtractor';
import { CandidateThemeGenerator } from '../modules/CandidateThemeGenerator';
import { CandidateWeightEngine } from '../modules/CandidateWeightEngine';
import { PromptComposer } from '../modules/PromptComposer';
import { VideoGenerator } from '../modules/VideoGenerator';
import { UploaderScheduler } from '../modules/UploaderScheduler';
import { ChannelConfig, PipelineResult, ShortsData } from '../types';

// Vercel Serverless Config
// Attempt to increase timeout to 60s (Max for Hobby/Pro limits apply)
export const config = {
  maxDuration: 60, 
};

export default async function handler(req: any, res: any) {
  const logs: string[] = [];
  const log = (msg: string) => {
    console.log(`[Pipeline] ${msg}`);
    logs.push(msg);
  };

  log("Request Received");

  // 1. Method Validation
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // 2. Environment Diagnostics
  const envStatus = {
    API_KEY: process.env.API_KEY ? "OK" : "MISSING",
    GOOGLE_CLIENT_ID: process.env.GOOGLE_CLIENT_ID ? "OK" : "MISSING",
    GOOGLE_CLIENT_SECRET: process.env.GOOGLE_CLIENT_SECRET ? "OK" : "MISSING",
    GOOGLE_REDIRECT_URI: process.env.GOOGLE_REDIRECT_URI || "MISSING"
  };
  console.log("Environment Diagnostics:", JSON.stringify(envStatus, null, 2));

  if (!process.env.API_KEY) {
    log("CRITICAL: API_KEY is missing from server environment.");
    return res.status(500).json({ 
        success: false, 
        logs, 
        error: 'Server Misconfiguration: API_KEY missing. Check Vercel Environment Variables.' 
    });
  }

  try {
    // 3. Input Validation
    const { channelConfig, forceMock } = req.body as { channelConfig: ChannelConfig, forceMock?: boolean };

    if (!channelConfig) {
        throw new Error("Invalid Input: 'channelConfig' is required.");
    }

    log(`🚀 Starting Automation for Channel: ${channelConfig.name} (${channelConfig.id})`);

    // --- Step 0: Trend Search (Real or Mock) ---
    const searcher = new TrendSearcher();
    let shortsData: ShortsData[];

    try {
        if (forceMock) {
            log("⚠️ Force Mock Data enabled.");
            shortsData = (searcher as any).getMockData();
        } else {
            // Safety check for TrendSearcher dependencies
            if (!channelConfig.auth && !process.env.GOOGLE_CLIENT_ID) {
                log("⚠️ No Auth & No Client ID. Falling back to Mock to prevent crash.");
                shortsData = (searcher as any).getMockData();
            } else {
                shortsData = await searcher.execute(channelConfig);
            }
        }
    } catch (e: any) {
        log(`⚠️ Trend Search Failed: ${e.message}. Using Mock Data fallback.`);
        shortsData = (searcher as any).getMockData();
    }

    log(`✅ Trends Fetched: ${shortsData.length} items`);

    // --- Step 1: Extract Signals ---
    const extractor = new TrendSignalExtractor();
    const trendSignals = await extractor.execute(shortsData);
    log("✅ Signals Extracted");

    // --- Step 2: Generate Candidates ---
    const candidateGen = new CandidateThemeGenerator();
    const candidates = await candidateGen.execute(trendSignals);
    log(`✅ Candidates Generated: ${candidates.length}`);

    // --- Step 3: Weight & Select ---
    const weightEngine = new CandidateWeightEngine();
    const scoredCandidates = await weightEngine.execute({
        candidates,
        channelState: channelConfig.channelState
    });
    const winner = scoredCandidates.find(c => c.selected);
    if (!winner) throw new Error("No winner selected by Weight Engine.");
    log(`✅ Winner Selected: ${winner.id} (${winner.total_score} pts)`);

    // --- Step 4: Compose Prompt ---
    const composer = new PromptComposer();
    const promptOutput = await composer.execute(winner);
    log("✅ Prompt & Metadata Composed");

    // --- Step 5: Generate Video (Veo) ---
    const videoGen = new VideoGenerator();
    let videoAsset;
    try {
        videoAsset = await videoGen.execute(promptOutput);
        log("✅ Video Generated (Veo 3.1 9:16)");
    } catch (e: any) {
        log(`⚠️ Video Generation Failed: ${e.message}`);
        throw new Error(`Video Gen Error: ${e.message}. Possible Vercel Timeout or API limit.`);
    }

    // --- Step 6: Upload to YouTube ---
    const uploader = new UploaderScheduler();

    // Construct Uploader Input
    const uploadInput = {
        video_asset: videoAsset,
        metadata: promptOutput,
        schedule: channelConfig.schedule,
        authCredentials: channelConfig.auth || undefined
    };

    let uploadResult;
    try {
        uploadResult = await uploader.execute(uploadInput);
        log(`✅ Upload Process Complete. Status: ${uploadResult.status}`);
    } catch (e: any) {
         log(`⚠️ Upload Failed: ${e.message}`);
         // We don't throw here, we return what we have so far
         uploadResult = { status: 'failed', platform_url: '', video_id: '', uploaded_at: new Date().toISOString() };
    }

    if (uploadResult.status === 'uploaded' || uploadResult.status === 'scheduled') {
        log(`🔗 URL: ${uploadResult.platform_url}`);
    }

    const result: PipelineResult = {
        success: true,
        logs: logs,
        videoUrl: videoAsset.video_url,
        uploadId: (uploadResult as any).video_id
    };

    return res.status(200).json(result);

  } catch (error: any) {
    console.error("CRITICAL PIPELINE FAILURE:", error);
    log(`❌ Fatal Error: ${error.message}`);

    // Ensure we return 200 with error details so frontend can display logs instead of generic 500
    return res.status(200).json({ 
        success: false, 
        logs, 
        error: error.message,
        stack: process.env.NODE_ENV === 'development' ? error.stack : undefined
    });
  }
}

import { GoogleGenAI } from "@google/genai";
import { Buffer } from 'buffer';

// Safe access to process.env to prevent browser crashes if this file is bundled
const getEnv = (key: string) => {
  if (typeof process !== 'undefined' && process.env) {
    return process.env[key];
  }
  return '';
};

const API_KEY = getEnv('API_KEY');

// Initialize conditionally to allow file to be imported without crashing
const ai = API_KEY ? new GoogleGenAI({ apiKey: API_KEY }) : null;

const textModelId = "gemini-2.5-flash";
const videoModelId = "veo-3.1-fast-generate-preview";

export const generateJSON = async <T>(
  prompt: string,
  systemInstruction: string,
  responseSchema?: any
): Promise<T> => {
  if (!ai || !API_KEY) {
    throw new Error("Server Error: API_KEY is missing. Please check Vercel environment variables.");
  }

  try {
    const response = await ai.models.generateContent({
      model: textModelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.2, 
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No text returned from Gemini.");
    }

    return JSON.parse(text) as T;
  } catch (error: any) {
    console.error("Gemini API Error (Text):", error);
    throw new Error(`Text Gen Failed: ${error.message}`);
  }
};

export const generateVideo = async (prompt: string): Promise<string> => {
  if (!ai || !API_KEY) {
    throw new Error("Server Error: API_KEY is missing.");
  }

  // Vercel Hobby limits functions to 10s (sometimes 60s). Veo takes longer.
  // We add a safety timeout to fail gracefully instead of hard crashing the function.
  const TIMEOUT_MS = 55000; // 55 seconds safety margin

  const generatePromise = async () => {
    try {
      console.log("Starting Veo generation (Server-Side)...");
      let operation = await ai.models.generateVideos({
        model: videoModelId,
        prompt: prompt,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: '9:16'
        }
      });

      // Polling loop
      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 5000));
        operation = await ai.operations.getVideosOperation({operation: operation});
        console.log("Polling status:", operation.metadata?.state);
      }

      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (!downloadLink) {
        throw new Error("Video generation completed but no URI returned.");
      }

      // Fetch the raw MP4 bytes using the API Key
      const response = await fetch(`${downloadLink}&key=${API_KEY}`);
      if (!response.ok) {
        throw new Error(`Failed to download video bytes: ${response.statusText}`);
      }

      const arrayBuffer = await response.arrayBuffer();

      // Server-side buffer handling
      let base64 = '';
      if (typeof Buffer !== 'undefined') {
          base64 = Buffer.from(arrayBuffer).toString('base64');
      } else {
          // Fallback or Error
          throw new Error("Environment does not support Buffer (Client-side execution blocked).");
      }

      return `data:video/mp4;base64,${base64}`;

    } catch (error: any) {
      console.error("Gemini API Error (Video):", error);
      throw error;
    }
  };

  // Race between Generation and Timeout
  return Promise.race([
    generatePromise(),
    new Promise<string>((_, reject) => 
        setTimeout(() => reject(new Error("Video Generation Timed Out (Vercel limit reached).")), TIMEOUT_MS)
    )
  ]);
};

import { google } from 'googleapis';

const CLIENT_ID = process.env.GOOGLE_CLIENT_ID;
const CLIENT_SECRET = process.env.GOOGLE_CLIENT_SECRET;
const REDIRECT_URI = process.env.GOOGLE_REDIRECT_URI || 'http://localhost:3000/';

export default async function handler(req: any, res: any) {
  try {
      // Diagnostic check
      if (!CLIENT_ID || !CLIENT_SECRET) {
          console.error("Missing Google OAuth Env Vars");
          return res.status(500).json({ 
              error: 'Server Misconfiguration: GOOGLE_CLIENT_ID or SECRET missing.' 
          });
      }

      const oauth2Client = new google.auth.OAuth2(
        CLIENT_ID,
        CLIENT_SECRET,
        REDIRECT_URI
      );

      // 1. Generate Auth URL (GET)
      if (req.method === 'GET') {
        const { action } = req.query;

        if (action === 'url') {
          const scopes = [
            'https://www.googleapis.com/auth/youtube.upload',
            'https://www.googleapis.com/auth/youtube.readonly'
          ];

          const url = oauth2Client.generateAuthUrl({
            access_type: 'offline',
            scope: scopes,
            prompt: 'consent' // Force refresh token
          });

          return res.status(200).json({ url });
        }
      }

      // 2. Exchange Code for Tokens (POST)
      if (req.method === 'POST') {
        const { code } = req.body;
        if (!code) {
          return res.status(400).json({ error: 'Missing auth code' });
        }

        try {
          const { tokens } = await oauth2Client.getToken(code);
          return res.status(200).json({ tokens });
        } catch (error: any) {
          console.error('Error exchanging token:', error);
          return res.status(500).json({ error: 'Failed to exchange token: ' + error.message });
        }
      }

      return res.status(400).json({ error: 'Invalid request method' });

  } catch (error: any) {
      console.error("Auth Endpoint Error:", error);
      return res.status(500).json({ error: error.message || "Internal Server Error" });
  }
}

import React, { useState, useEffect, Suspense } from 'react';
import { 
  ChannelConfig, LogEntry, ChannelState, ScheduleConfig, PipelineResult, AuthCredentials 
} from './types';
import { MOCK_CHANNEL_STATE } from './constants';

interface ErrorBoundaryProps {
  children: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// Error Boundary Component
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-slate-900 flex items-center justify-center text-red-400 p-8 text-center">
          <div>
            <h1 className="text-3xl font-bold mb-4">系統發生錯誤 ⚠️</h1>
            <p className="bg-slate-800 p-4 rounded text-left font-mono text-sm max-w-2xl overflow-auto">
              {this.state.error?.message || "Unknown Error"}
            </p>
            <button 
                onClick={() => window.location.reload()}
                className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-500"
            >
                重新整理
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

const AppContent: React.FC = () => {
  // --- State ---
  const [channels, setChannels] = useState<ChannelConfig[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isAdding, setIsAdding] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'logs'>('dashboard');
  const [isLoading, setIsLoading] = useState(true);

  // New Channel Form State
  const [newChannelName, setNewChannelName] = useState("");
  const [newKeywords, setNewKeywords] = useState("AI, Tech");
  const [newRegion, setNewRegion] = useState("US");

  // --- Persistence & Init ---
  useEffect(() => {
    try {
        const saved = localStorage.getItem('sas_channels');
        if (saved) setChannels(JSON.parse(saved));

        // Handle OAuth Callback
        const params = new URLSearchParams(window.location.search);
        const code = params.get('code');
        const pendingId = localStorage.getItem('sas_pending_auth_id');

        if (code && pendingId) {
            handleAuthCallback(code, pendingId);
        }
    } catch (e) {
        console.error("Init Error:", e);
    } finally {
        setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (!isLoading) {
        localStorage.setItem('sas_channels', JSON.stringify(channels));
    }
  }, [channels, isLoading]);

  // --- Actions ---

  const addLog = (channelId: string, channelName: string, level: 'info' | 'success' | 'error', msg: string) => {
    const entry: LogEntry = {
      id: Date.now().toString() + Math.random(),
      timestamp: new Date().toLocaleTimeString(),
      channelId,
      channelName,
      level,
      message: msg
    };
    setLogs(prev => [entry, ...prev]);
  };

  const handleAuthCallback = async (code: string, channelId: string) => {
    window.history.replaceState({}, document.title, window.location.pathname);
    localStorage.removeItem('sas_pending_auth_id');

    addLog(channelId, 'System', 'info', 'Exchanging OAuth Code...');
    try {
      const res = await fetch('/api/auth', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ code })
      });
      const data = await res.json();
      if (data.tokens) {
        updateChannel(channelId, { auth: data.tokens });
        addLog(channelId, 'System', 'success', 'YouTube 授權成功！');
      }
    } catch (e) {
      addLog(channelId, 'System', 'error', '授權失敗');
    }
  };

  const createChannel = () => {
    const newId = Date.now().toString();
    const newChannel: ChannelConfig = {
      id: newId,
      name: newChannelName || "New Channel",
      regionCode: newRegion,
      searchKeywords: newKeywords.split(',').map(s => s.trim()),
      channelState: { ...MOCK_CHANNEL_STATE, niche: newKeywords },
      schedule: { active: false, privacy_status: 'private' },
      auth: null,
      status: 'idle'
    };
    setChannels(prev => [...prev, newChannel]);
    setIsAdding(false);
    setNewChannelName("");
  };

  const deleteChannel = (id: string) => {
    setChannels(prev => prev.filter(c => c.id !== id));
  };

  const updateChannel = (id: string, updates: Partial<ChannelConfig>) => {
    setChannels(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  };

  const startAuth = async (channelId: string) => {
    localStorage.setItem('sas_pending_auth_id', channelId);
    try {
        const res = await fetch('/api/auth?action=url');
        const data = await res.json();
        if (data.url) window.location.href = data.url;
        else alert("無法獲取授權 URL，請檢查 Server Config (Client ID)");
    } catch (e) {
        alert("API 請求失敗，請確認後端是否運行。");
