    setActiveChannelId(channel.id);
    setPipelineState(prev => ({ ...prev, [channel.id]: { currentStep: 0, status: 'running' } }));
    addLog(channel.id, 'info', '啟動全自動流水線...');

    try {
      const res = await fetch('/api/pipeline', {
        method: 'POST',
