export default App;

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-slate-950 text-slate-200 antialiased;
  }
}

@layer utilities {
  .animate-fade-in {
    animation: fadeIn 0.6s cubic-bezier(0.16, 1, 0.3, 1);
  }
  .animate-slide-down {
    animation: slideDown 0.4s cubic-bezier(0.16, 1, 0.3, 1);
  }

  .custom-scrollbar::-webkit-scrollbar {
    width: 5px;
  }
  .custom-scrollbar::-webkit-scrollbar-track {
    @apply bg-transparent;
  }
  .custom-scrollbar::-webkit-scrollbar-thumb {
    @apply bg-slate-800 rounded-full hover:bg-slate-700 transition-colors;
  }
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(15px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes slideDown {
  from { opacity: 0; transform: translateY(-20px); }
  to { opacity: 1; transform: translateY(0); }
}

import React, { useState, useEffect } from 'react';
import { 
  ChannelConfig, LogEntry, PipelineResult, TestResult 
} from './types';
import { MOCK_CHANNEL_STATE } from './constants';
import { ModuleCard } from './components/ModuleCard';

// Test Runners
import { runTrendExtractorTests } from './tests/TrendSignalExtractor.test';
import { runCandidateGeneratorTests } from './tests/CandidateThemeGenerator.test';
import { runWeightEngineTests } from './tests/CandidateWeightEngine.test';
import { runPromptComposerTests } from './tests/PromptComposer.test';
import { runVideoGeneratorTests } from './tests/VideoGenerator.test';
import { runUploaderTests } from './tests/UploaderScheduler.test';

const App: React.FC = () => {
  const [channels, setChannels] = useState<ChannelConfig[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [activeChannelId, setByChannelId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'logs'>('dashboard');

  const [pipelineStates, setPipelineStates] = useState<Record<string, any>>({});
  const [testResults, setTestResults] = useState<Record<string, any>>({});

  // Form State
  const [newChannelName, setNewChannelName] = useState("");
  const [newKeywords, setNewKeywords] = useState("AI, Tech, Science");

  useEffect(() => {
    const saved = localStorage.getItem('sas_channels_v2');
    if (saved) {
      setChannels(JSON.parse(saved));
    } else {
      // Initialize with a mock channel for demo
      const demo: ChannelConfig = {
        id: 'demo-1',
        name: 'AI 探索實驗室',
        regionCode: 'US',
        searchKeywords: ['AI', 'Science'],
        channelState: MOCK_CHANNEL_STATE,
        schedule: { active: false, privacy_status: 'private' },
        auth: null,
        status: 'idle'
      };
      setChannels([demo]);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('sas_channels_v2', JSON.stringify(channels));
  }, [channels]);

  const addLog = (channelId: string, level: 'info' | 'success' | 'error', msg: string) => {
    const entry: LogEntry = {
      id: Math.random().toString(),
      timestamp: new Date().toLocaleTimeString(),
      channelId,
      channelName: channels.find(c => c.id === channelId)?.name || 'System',
      level,
      message: msg
    };
    setLogs(prev => [entry, ...prev]);
  };

  const createChannel = () => {
    if (!newChannelName) return;
    const newChannel: ChannelConfig = {
      id: Date.now().toString(),
      name: newChannelName,
      regionCode: "US",
      searchKeywords: newKeywords.split(',').map(s => s.trim()),
      channelState: { ...MOCK_CHANNEL_STATE, niche: newKeywords },
      schedule: { active: false, privacy_status: 'private' },
      auth: null,
      status: 'idle'
    };
    setChannels([...channels, newChannel]);
    setIsAdding(false);
    setNewChannelName("");
  };

  const deleteChannel = (id: string) => {
    setChannels(channels.filter(c => c.id !== id));
    if (activeChannelId === id) setByChannelId(null);
  };

  // Improved runPipeline with simulation fallback
  const runPipeline = async (channel: ChannelConfig) => {
    setByChannelId(channel.id);
    addLog(channel.id, 'info', '開始執行全自動流水線...');

    // Initial State: Running Step 1
    setPipelineStates(prev => ({ 
      ...prev, 
      [channel.id]: { currentStep: 1, status: 'running' } 
    }));

    try {
      const res = await fetch('/api/pipeline', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ channelConfig: channel })
      });

      if (!res.ok) throw new Error("API Route Not Found or Failed");

      const result: PipelineResult = await res.json();

      if (result.success) {
        addLog(channel.id, 'success', '流水線執行成功！');
        setPipelineStates(prev => ({ 
          ...prev, 
          [channel.id]: { status: 'success', data: result, currentStep: 7 } 
        }));
      } else {
        throw new Error(result.error);
      }
    } catch (e: any) {
      addLog(channel.id, 'info', 'API 未偵測到，切換至本地模擬模式...');
      simulatePipeline(channel.id);
    }
  };

  // Mocking the pipeline steps visually
  const simulatePipeline = async (channelId: string) => {
    const steps = [1, 2, 3, 4, 5, 6];
    for (const step of steps) {
      setPipelineStates(prev => ({ 
        ...prev, 
        [channelId]: { currentStep: step, status: 'running' } 
      }));
      addLog(channelId, 'info', `正在執行模組步驟 0${step}...`);
      await new Promise(r => setTimeout(r, 1500));
    }

    addLog(channelId, 'success', '模擬流程完成！影片已備妥。');
    setPipelineStates(prev => ({ 
      ...prev, 
      [channelId]: { 
        status: 'success', 
        currentStep: 7,
        data: {
          logs: ["Simulated: Extraction Complete", "Simulated: Candidate Chosen"],
          videoUrl: "https://storage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4" 
        } 
      } 
    }));
  };

  const getModuleStatus = (channelId: string, step: number) => {
    const state = pipelineStates[channelId];
    if (!state) return 'idle';
    if (state.status === 'error' && state.currentStep === step) return 'error';
    if (state.status === 'success' || state.currentStep > step) return 'success';
    if (state.currentStep === step && state.status === 'running') return 'loading';
    return 'idle';
  };

  return (
    <div className="flex min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500/30">

      {/* SIDEBAR */}
      <aside className="w-72 bg-slate-900 border-r border-slate-800 flex flex-col fixed inset-y-0 z-50">
        <div className="p-8">
          <div className="flex items-center gap-3 mb-10 group cursor-default">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center font-black text-white shadow-lg">S</div>
            <h1 className="font-bold text-xl tracking-tight text-white">Shorts AI</h1>
          </div>

          <nav className="space-y-1">
            <button 
              onClick={() => { setActiveTab('dashboard'); setByChannelId(null); }}
              className={`w-full text-left px-4 py-3 rounded-xl transition-all flex items-center gap-3 ${activeTab === 'dashboard' && !activeChannelId ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              📊 <span className="text-sm">儀表板總覽</span>
            </button>
            <button 
              onClick={() => setActiveTab('logs')}
              className={`w-full text-left px-4 py-3 rounded-xl transition-all flex items-center gap-3 ${activeTab === 'logs' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              📜 <span className="text-sm">操作日誌</span>
            </button>
          </nav>

          <div className="mt-12">
            <div className="flex items-center justify-between mb-4 px-2">
               <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">我的頻道</p>
               <button onClick={() => setIsAdding(true)} className="text-indigo-400 text-xs font-bold">+</button>
            </div>
            <div className="space-y-1">
              {channels.map(c => (
                <div key={c.id} className="group flex items-center gap-1">
                  <button 
                    onClick={() => { setByChannelId(c.id); setActiveTab('dashboard'); }}
                    className={`flex-1 text-left px-4 py-2 rounded-lg text-xs transition-all truncate ${activeChannelId === c.id ? 'bg-slate-800 text-indigo-400 font-bold' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    {c.name}
                  </button>
                  <button onClick={() => deleteChannel(c.id)} className="opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-red-400">✕</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      </aside>

      {/* MAIN */}
      <main className="flex-1 ml-72">
        <header className="h-20 border-b border-slate-800 flex items-center justify-between px-10 bg-slate-950/80 backdrop-blur-md sticky top-0 z-40">
          <h2 className="font-bold text-lg text-white">
            {activeChannelId ? `執行中：${channels.find(c => c.id === activeChannelId)?.name}` : '系統狀態'}
          </h2>
          <div className="flex items-center gap-4">
             <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
             <span className="text-xs font-medium text-slate-400 tracking-wide uppercase">Gemini 3.0 API 在線</span>
          </div>
        </header>

        <div className="p-10 max-w-5xl mx-auto">
          {activeTab === 'dashboard' && !activeChannelId && (
            <div className="space-y-8 animate-fade-in">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {isAdding && (
                  <div className="bg-slate-900 p-8 rounded-3xl border border-indigo-500/50 shadow-2xl">
                    <h3 className="font-bold text-white mb-6">新增自動化頻道</h3>
                    <div className="space-y-4">
                      <input 
                        placeholder="頻道名稱" 
                        value={newChannelName} onChange={e => setNewChannelName(e.target.value)}
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl p-3.5 text-sm focus:border-indigo-500 outline-none" 
                      />
                      <input 
                        placeholder="主題關鍵字" 
                        value={newKeywords} onChange={e => setNewKeywords(e.target.value)}
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl p-3.5 text-sm focus:border-indigo-500 outline-none" 
                      />
                      <button onClick={createChannel} className="w-full bg-indigo-600 py-3.5 rounded-xl text-sm font-bold shadow-lg shadow-indigo-500/20">確認新增</button>
                      <button onClick={() => setIsAdding(false)} className="w-full text-slate-500 text-xs py-2">取消</button>
                    </div>
                  </div>
                )}

                {channels.map(c => (
                  <div key={c.id} className="bg-slate-900 p-8 rounded-3xl border border-slate-800 hover:border-indigo-500/40 transition-all group">
                    <div className="w-12 h-12 bg-slate-800 rounded-2xl flex items-center justify-center text-xl mb-6 shadow-inner">📺</div>
                    <h3 className="font-bold text-xl text-white mb-2">{c.name}</h3>
                    <p className="text-xs text-slate-500 mb-8 leading-relaxed">分析標籤: {c.searchKeywords.join(', ')}</p>
                    <button 
                      onClick={() => runPipeline(c)}
                      className="w-full py-3.5 bg-slate-800 group-hover:bg-indigo-600 rounded-2xl text-sm font-bold transition-all shadow-md active:scale-95"
                    >
                      🚀 開始自動化流程
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'dashboard' && activeChannelId && (
            <div className="space-y-10 animate-fade-in">
               <div className="flex items-center justify-between bg-slate-900 p-10 rounded-3xl border border-slate-800">
                  <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-indigo-600/20 rounded-2xl flex items-center justify-center text-3xl">⚙️</div>
                    <div>
                      <h3 className="font-bold text-2xl text-white mb-1">{channels.find(c => c.id === activeChannelId)?.name}</h3>
                      <p className="text-sm text-slate-500">正在監測流水線階段...</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => runPipeline(channels.find(c => c.id === activeChannelId)!)}
                    className="px-8 py-3.5 bg-indigo-600 rounded-2xl text-sm font-bold shadow-xl shadow-indigo-500/20 active:scale-95"
                  >
                    重啟流水線
                  </button>
               </div>

               <div className="space-y-6">
                  <ModuleCard 
                    title="趨勢信號提取" stepNumber="01" description="從 YouTube 抓取並分析最新趨勢數據"
                    status={getModuleStatus(activeChannelId, 1)}
                    onRunTest={async () => runTrendExtractorTests()}
                    onExecute={() => {}} canExecute={true} data={pipelineStates[activeChannelId]?.data?.logs} testResult={testResults.trend}
                  />

                  <ModuleCard 
                    title="題材候選生成" stepNumber="02" description="Gemini 生成 3 個潛在病毒式影片題材"
                    status={getModuleStatus(activeChannelId, 2)}
                    onRunTest={async () => runCandidateGeneratorTests()}
                    onExecute={() => {}} canExecute={true} data={null} testResult={testResults.cand}
                  />

                  <ModuleCard 
                    title="權重評分引擎" stepNumber="03" description="評估並選出最符合頻道屬性的題材"
                    status={getModuleStatus(activeChannelId, 3)}
                    onRunTest={async () => runWeightEngineTests()}
                    onExecute={() => {}} canExecute={true} data={null} testResult={testResults.weight}
                  />

                  <ModuleCard 
                    title="影片資產排版" stepNumber="04" description="撰寫影片 Prompt、標題與 SEO 描述"
                    status={getModuleStatus(activeChannelId, 4)}
                    onRunTest={async () => runPromptComposerTests()}
                    onExecute={() => {}} canExecute={true} data={null} testResult={testResults.composer}
                  />

                  <ModuleCard 
                    title="影片生成 (Veo)" stepNumber="05" description="使用 Google Veo 生成 9:16 短影片資產"
                    status={getModuleStatus(activeChannelId, 5)}
                    onRunTest={async () => runVideoGeneratorTests()}
                    onExecute={() => {}} canExecute={true} data={null} testResult={testResults.video}
                  >
                    {pipelineStates[activeChannelId]?.data?.videoUrl && (
                      <div className="mt-8 rounded-3xl overflow-hidden border border-slate-700 bg-black aspect-[9/16] max-w-[300px] mx-auto shadow-2xl">
                         <video src={pipelineStates[activeChannelId].data.videoUrl} controls className="w-full h-full object-cover" />
                      </div>
                    )}
                  </ModuleCard>

                  <ModuleCard 
                    title="發佈與排程" stepNumber="06" description="自動上傳至 YouTube 並設定發佈狀態"
                    status={getModuleStatus(activeChannelId, 6)}
                    onRunTest={async () => runUploaderTests()}
                    onExecute={() => {}} canExecute={true} data={null} testResult={testResults.uploader}
                  />
               </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-slate-900 rounded-3xl border border-slate-800 overflow-hidden shadow-2xl">
              <div className="p-6 bg-slate-800/50 border-b border-slate-800 flex justify-between items-center font-bold">系統活動全日誌</div>
              <div className="divide-y divide-slate-800 max-h-[70vh] overflow-y-auto custom-scrollbar">
                {logs.length === 0 ? (
                  <div className="p-20 text-center text-slate-600 italic">目前沒有日誌數據</div>
                ) : logs.map(l => (
                  <div key={l.id} className="p-6 hover:bg-slate-800/20 transition-all flex gap-6">
                    <span className="text-[10px] font-mono text-slate-500 mt-1">{l.timestamp}</span>
                    <div>
                      <span className={`text-[10px] font-black px-2 py-0.5 rounded-md mr-3 ${l.level === 'error' ? 'bg-red-900/40 text-red-400' : 'bg-indigo-900/40 text-indigo-400'}`}>
                        {l.level.toUpperCase()}
                      </span>
                      <span className="text-sm font-bold text-slate-300">{l.channelName}</span>
                      <p className="text-sm text-slate-400 mt-2 leading-relaxed">{l.message}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

