    <div className="flex min-h-screen bg-[#020617] text-slate-200 antialiased overflow-hidden">

      {/* --- 側邊導覽 --- */}
      <aside className="w-80 bg-slate-900/40 border-r border-slate-800 flex flex-col fixed inset-y-0 z-50 backdrop-blur-2xl">
        <div className="p-10">
          <div className="flex items-center gap-4 mb-16">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-2xl shadow-indigo-500/20">S</div>
            <div>
              <h1 className="font-bold text-xl tracking-tight text-white leading-none">Shorts AI</h1>
              <p className="text-[10px] text-indigo-400 font-black uppercase tracking-widest mt-1">v2.3.6 Stable</p>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => { setActiveTab('dashboard'); setByChannelId(null); }}
              className={`w-full text-left px-5 py-4 rounded-2xl transition-all flex items-center gap-4 ${activeTab === 'dashboard' && !activeChannelId ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-500/20' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-200'}`}
            >
              <span className="text-xl">📊</span> <span className="text-sm font-bold">總覽儀表板</span>
            </button>
            <button 
              onClick={() => setActiveTab('logs')}
              className={`w-full text-left px-5 py-4 rounded-2xl transition-all flex items-center gap-4 ${activeTab === 'logs' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-500/20' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-200'}`}
            >
              <span className="text-xl">📜</span> <span className="text-sm font-bold">系統日誌</span>
            </button>
          </nav>

          <div className="mt-16">
            <div className="flex items-center justify-between mb-6 px-3">
               <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">頻道監控</p>
               <button onClick={() => setIsAdding(true)} className="w-6 h-6 rounded-full bg-slate-800 flex items-center justify-center text-indigo-400 hover:bg-indigo-600 transition-all">+</button>
            </div>
            <div className="space-y-1">
              {channels.map(c => (
                <div key={c.id} className="group flex items-center gap-1">
                  <button 
                    onClick={() => { setByChannelId(c.id); setActiveTab('dashboard'); }}
                    className={`flex-1 text-left px-5 py-3 rounded-xl text-xs transition-all truncate border ${activeChannelId === c.id ? 'bg-indigo-600/10 text-indigo-400 border-indigo-500/30' : 'text-slate-500 border-transparent hover:text-slate-300 hover:bg-slate-800/30'}`}
                  >
                    {c.name}
                  </button>
                  <button onClick={() => deleteChannel(c.id)} className="opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-red-400">✕</button>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-auto p-8 border-t border-slate-800/50">
           <div className="flex items-center gap-3">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_#22c55e]"></div>
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">System Engine Ready</span>
           </div>
        </div>
      </aside>

      {/* --- 主內容 --- */}
      <main className="flex-1 ml-80 h-screen overflow-y-auto bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-950/10 via-slate-950 to-slate-950">
        <header className="h-24 border-b border-slate-800/50 flex items-center justify-between px-12 bg-slate-950/80 backdrop-blur-xl sticky top-0 z-40">
          <div>
            <h2 className="font-black text-2xl text-white tracking-tight">
              {activeChannelId ? channels.find(c => c.id === activeChannelId)?.name : '核心系統監控中'}
            </h2>
            <p className="text-[10px] text-slate-500 mt-1 uppercase tracking-widest font-bold">Automation Pipeline Dashboard</p>
          </div>
          <div className="flex items-center gap-6">
             <div className="w-10 h-10 rounded-xl bg-slate-800 flex items-center justify-center text-slate-400 text-lg">⚙️</div>
          </div>
        </header>

        <div className="p-12 max-w-6xl mx-auto">
          {activeTab === 'dashboard' && !activeChannelId && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 animate-fade-in">
              {isAdding && (
                <div className="bg-slate-900 p-10 rounded-[2.5rem] border-2 border-indigo-500/50 shadow-2xl">
                  <h3 className="font-bold text-white mb-6">新增自動化頻道</h3>
                  <div className="space-y-4">
                    <input 
                      placeholder="頻道名稱" 
                      value={newChannelName} onChange={e => setNewChannelName(e.target.value)}
                      className="w-full bg-slate-800 border border-slate-700 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none transition-all" 
                    />
                    <input 
                      placeholder="關鍵字標籤" 
                      value={newKeywords} onChange={e => setNewKeywords(e.target.value)}
                      className="w-full bg-slate-800 border border-slate-700 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none transition-all" 
                    />
                    <button onClick={createChannel} className="w-full bg-indigo-600 py-4 rounded-2xl text-sm font-black shadow-lg shadow-indigo-500/20 active:scale-95 transition-all">確認儲存</button>
                    <button onClick={() => setIsAdding(false)} className="w-full text-slate-500 text-xs py-2">取消操作</button>
                  </div>
                </div>
              )}

              {channels.map(c => (
                <div key={c.id} className="bg-slate-900/50 p-10 rounded-[2.5rem] border border-slate-800 hover:border-indigo-500/50 transition-all group shadow-xl">
                  <div className="w-14 h-14 bg-slate-800 rounded-2xl flex items-center justify-center text-2xl mb-8 shadow-inner">📺</div>
                  <h3 className="font-black text-2xl text-white mb-2">{c.name}</h3>
                  <p className="text-xs text-slate-500 h-10 mb-8 leading-relaxed">標籤: {c.searchKeywords.join(', ')}</p>
                  <button 
                    onClick={() => runPipeline(c)}
                    className="w-full py-5 bg-slate-800 group-hover:bg-indigo-600 rounded-2xl text-sm font-black transition-all shadow-md active:scale-95"
                  >
                    🚀 啟動自動化流程
                  </button>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'dashboard' && activeChannelId && (
            <div className="space-y-10 animate-fade-in pb-20">
               <div className="flex items-center justify-between bg-slate-900/60 p-12 rounded-[3rem] border border-slate-800 shadow-2xl backdrop-blur-sm">
                  <div className="flex items-center gap-8">
                    <div className="w-20 h-20 bg-indigo-600/10 rounded-3xl flex items-center justify-center text-4xl border border-indigo-500/20 shadow-inner">⚡</div>
                    <div>
                      <h3 className="font-black text-3xl text-white mb-2">{channels.find(c => c.id === activeChannelId)?.name}</h3>
                      <p className="text-sm text-slate-500">Pipeline Visualization Monitor</p>
