                  </div>
                  <button 
                    onClick={() => runPipeline(channels.find(c => c.id === activeChannelId)!)}
                    className="px-10 py-5 bg-indigo-600 hover:bg-indigo-500 rounded-2xl text-sm font-black shadow-2xl shadow-indigo-500/30 active:scale-95 transition-all"
                  >
                    重新執行
                  </button>
               </div>

               <div className="space-y-8 max-w-4xl mx-auto">
                  <ModuleCard 
                    title="趨勢信號提取" stepNumber="01" description="從 YouTube 數據庫分析熱門信號"
                    status={getModuleStatus(activeChannelId, 1)}
                    onRunTest={() => handleRunTest('trend', runTrendExtractorTests)}
                    onExecute={() => {}} canExecute={true} data={pipelineStates[activeChannelId]?.data?.logs} 
                    testResult={testResults.trend || null}
                  />

                  <ModuleCard 
                    title="題材候選生成" stepNumber="02" description="Gemini 生成 3 個潛在病毒式影片構思"
                    status={getModuleStatus(activeChannelId, 2)}
                    onRunTest={() => handleRunTest('cand', runCandidateGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.cand || null}
                  />

                  <ModuleCard 
                    title="影片生成 (Veo)" stepNumber="05" description="生成 9:16 高解析度短影片"
                    status={getModuleStatus(activeChannelId, 5)}
                    onRunTest={() => handleRunTest('video', runVideoGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
