          {activeTab === 'logs' && (
            <div className="bg-slate-900 rounded-[3rem] border border-slate-800 overflow-hidden shadow-2xl">
              <div className="p-8 bg-slate-800/40 border-b border-slate-800 flex justify-between items-center">
                 <span className="font-black text-white text-lg">系統活動記錄</span>
                 <button onClick={() => setLogs([])} className="text-xs text-slate-500 font-bold uppercase hover:text-red-400">清除記錄</button>
              </div>
              <div className="divide-y divide-slate-800/50 max-h-[70vh] overflow-y-auto custom-scrollbar">
