  const simulatePipeline = async (channelId: string) => {
    const steps = [1, 2, 3, 4, 5, 6];
    for (const step of steps) {
      setPipelineStates(prev => ({ 
        ...prev, 
        [channelId]: { currentStep: step, status: 'running' } 
      }));
      addLog(channelId, 'info', `正在執行模組：Step ${step}`);
      await new Promise(r => setTimeout(r, 1500));
    }

    addLog(channelId, 'success', '全模組模擬執行完畢！影片生成預覽已載入。');
    setPipelineStates(prev => ({ 
      ...prev, 
      [channelId]: { 
        status: 'success', 
        currentStep: 7,
        data: {
          logs: ["[模擬] 趨勢分析完成 (100%)", "[模擬] 候選題材生成完畢", "[模擬] 已選擇最優 Prompt"],
          videoUrl: "https://storage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4" 
        } 
      } 
    }));
  };

  const getModuleStatus = (channelId: string, step: number) => {
    const state = pipelineStates[channelId];
    if (!state) return 'idle';
    if (state.status === 'success' || state.currentStep > step) return 'success';
    if (state.currentStep === step && state.status === 'running') return 'loading';
    return 'idle';
  };

  // 修復 handleRunTest 的類型問題，確保符合 ModuleCard 的 Promise<TestResult> 要求
  const handleRunTest = async (moduleKey: string, testFn: () => Promise<TestResult>): Promise<TestResult> => {
    const res = await testFn();
    setTestResults(prev => ({ ...prev, [moduleKey]: res }));
    return res;
  };

  return (
    <div className="flex min-h-screen bg-[#020617] text-slate-200 antialiased font-sans">

      {/* 側邊導航欄 - 高科技氛圍 */}
      <aside className="w-80 bg-slate-900/50 border-r border-slate-800/60 flex flex-col fixed inset-y-0 z-50 backdrop-blur-3xl shadow-2xl">
        <div className="p-10">
          <div className="flex items-center gap-4 mb-16 group">
            <div className="w-12 h-12 bg-gradient-to-br from-indigo-600 via-violet-600 to-purple-600 rounded-[18px] flex items-center justify-center font-black text-white text-xl shadow-[0_0_30px_rgba(79,70,229,0.3)] group-hover:rotate-12 transition-all">S</div>
            <div>
              <h1 className="font-black text-xl tracking-tighter text-white leading-none">SHORTS AI</h1>
              <p className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.2em] mt-2 opacity-80">Automation Lab</p>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => { setActiveTab('dashboard'); setByChannelId(null); }}
              className={`w-full text-left px-6 py-4 rounded-2xl transition-all flex items-center gap-4 ${activeTab === 'dashboard' && !activeChannelId ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-500/30' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-200'}`}
            >
              <span className="text-xl opacity-80">📊</span> <span className="text-sm font-bold">控制台 Dashboard</span>
            </button>
            <button 
              onClick={() => setActiveTab('logs')}
              className={`w-full text-left px-6 py-4 rounded-2xl transition-all flex items-center gap-4 ${activeTab === 'logs' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-500/30' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-200'}`}
            >
              <span className="text-xl opacity-80">📜</span> <span className="text-sm font-bold">系統活動日誌</span>
            </button>
          </nav>

          <div className="mt-20">
            <div className="flex items-center justify-between mb-8 px-4">
               <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Active Channels</p>
               <button onClick={() => setIsAdding(true)} className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all shadow-inner">+</button>
            </div>
            <div className="space-y-2 max-h-[40vh] overflow-y-auto pr-2 custom-scrollbar">
              {channels.map(c => (
                <div key={c.id} className="group flex items-center gap-2">
                  <button 
                    onClick={() => { setByChannelId(c.id); setActiveTab('dashboard'); }}
                    className={`flex-1 text-left px-5 py-3.5 rounded-xl text-xs font-bold transition-all truncate border ${activeChannelId === c.id ? 'bg-indigo-600/10 text-indigo-400 border-indigo-500/40 shadow-[inset_0_0_20px_rgba(99,102,241,0.05)]' : 'text-slate-500 border-transparent hover:text-slate-300 hover:bg-slate-800/40'}`}
                  >
                    {c.name}
                  </button>
                  <button onClick={() => setChannels(channels.filter(x => x.id !== c.id))} className="opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-red-400 transition-opacity">✕</button>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-auto p-10 border-t border-slate-800/60 bg-slate-900/30">
           <div className="flex items-center gap-4">
              <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_12px_#22c55e]"></div>
              <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Core Engines Ready</span>
           </div>
        </div>
      </aside>

      {/* 主內容區域 - 網格與漸層背景 */}
      <main className="flex-1 ml-80 min-h-screen bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900/10 via-slate-950 to-slate-950 overflow-y-auto">
