          <div className="flex items-center gap-10">
             <div className="text-right">
                <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">System Load</p>
                <div className="w-32 h-1.5 bg-slate-800 rounded-full mt-2 overflow-hidden shadow-inner">
                   <div className="w-1/3 h-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.5)]"></div>
