        <div className="p-16 max-w-7xl mx-auto">
          {activeTab === 'dashboard' && !activeChannelId && (
            <div className="animate-fade-in space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
                {isAdding && (
                  <div className="bg-slate-900/80 p-12 rounded-[40px] border-2 border-indigo-500/50 shadow-[0_30px_60px_-12px_rgba(0,0,0,0.5),0_0_40px_rgba(79,70,229,0.1)] backdrop-blur-xl animate-slide-down">
