                      <div className="pt-4 flex flex-col gap-4">
                        <button onClick={createChannel} className="w-full bg-indigo-600 hover:bg-indigo-500 py-6 rounded-2xl text-sm font-black shadow-2xl shadow-indigo-600/30 transition-all transform active:scale-[0.98]">執行初始化部署</button>
                        <button onClick={() => setIsAdding(false)} className="w-full text-slate-500 text-xs font-black uppercase tracking-widest py-2 hover:text-slate-300">取消部署</button>
                      </div>
                    </div>
