                )}

                {channels.map(c => (
                  <div key={c.id} className="group bg-slate-900/40 p-12 rounded-[40px] border border-slate-800/60 hover:border-indigo-500/40 hover:bg-slate-900/60 transition-all relative overflow-hidden shadow-xl">
                    <div className="absolute top-0 right-0 p-8">
                      <div className="px-3 py-1 bg-green-500/10 rounded-full text-[9px] font-black text-green-400 uppercase tracking-widest border border-green-500/20">Active</div>
                    </div>
                    <div className="w-20 h-20 bg-slate-950 rounded-[24px] flex items-center justify-center text-4xl mb-10 shadow-inner border border-slate-800/50 group-hover:scale-110 transition-transform">📺</div>
                    <h3 className="font-black text-3xl text-white mb-4 tracking-tight group-hover:text-indigo-400 transition-colors">{c.name}</h3>
                    <p className="text-sm text-slate-500 font-medium line-clamp-2 leading-relaxed h-10 mb-12">Search Nodes: {c.searchKeywords.join(', ')}</p>
                    <button 
                      onClick={() => runPipeline(c)}
                      className="w-full py-6 bg-slate-900 group-hover:bg-indigo-600 rounded-[20px] text-sm font-black transition-all shadow-2xl shadow-black/20 active:scale-95 flex items-center justify-center gap-3 border border-slate-800 group-hover:border-transparent"
