                  <button 
                    onClick={() => runPipeline(channels.find(c => c.id === activeChannelId)!)}
                    className="px-12 py-6 bg-indigo-600 hover:bg-indigo-500 rounded-[22px] text-sm font-black shadow-2xl shadow-indigo-600/30 active:scale-[0.98] transition-all"
                  >
