                  </button>
               </div>

               {/* 模組流水線 */}
               <div className="space-y-10 max-w-5xl mx-auto">
                  <ModuleCard 
                    title="Phase 1: 趨勢信號提取" stepNumber="01" description="解析 YouTube 數據，計算動詞、主體與結構頻率。"
                    status={getModuleStatus(activeChannelId, 1) as any}
                    onRunTest={() => handleRunTest('trend', runTrendExtractorTests)}
                    onExecute={() => {}} canExecute={true} data={pipelineStates[activeChannelId]?.data?.logs} 
                    testResult={testResults.trend || null}
                  />

                  <ModuleCard 
                    title="Phase 2: 題材候選生成" stepNumber="02" description="Gemini 模擬生成 3 個具備病毒式傳播潛力的影片構思。"
                    status={getModuleStatus(activeChannelId, 2) as any}
                    onRunTest={() => handleRunTest('cand', runCandidateGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.cand || null}
                  />

                  <ModuleCard 
                    title="Phase 4: 提示詞優化器" stepNumber="04" description="撰寫精確的影片生成提示詞與 SEO 標籤。"
                    status={getModuleStatus(activeChannelId, 4) as any}
                    onRunTest={() => handleRunTest('composer', runPromptComposerTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.composer || null}
                  />

                  <ModuleCard 
                    title="Phase 5: 影片資產生成 (Veo 3.1)" stepNumber="05" description="呼叫 Google Veo 模型生成 9:16 高解析度影片資產。"
                    status={getModuleStatus(activeChannelId, 5) as any}
                    onRunTest={() => handleRunTest('video', runVideoGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.video || null}
                  >
                    {pipelineStates[activeChannelId]?.data?.videoUrl && (
                      <div className="mt-12 rounded-[40px] overflow-hidden border-8 border-slate-900 bg-black aspect-[9/16] max-w-[340px] mx-auto shadow-2xl ring-1 ring-slate-800">
                         <video src={pipelineStates[activeChannelId].data.videoUrl} controls autoPlay loop className="w-full h-full object-cover" />
                      </div>
                    )}
                  </ModuleCard>

                  <ModuleCard 
                    title="Phase 6: 上傳與排程器" stepNumber="06" description="自動推送影片至 YouTube Studio 並配置發佈策略。"
                    status={getModuleStatus(activeChannelId, 6) as any}
                    onRunTest={() => handleRunTest('uploader', runUploaderTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.uploader || null}
                  />
               </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-slate-900/60 rounded-[48px] border border-slate-800/60 overflow-hidden shadow-3xl animate-fade-in backdrop-blur-xl">
              <div className="p-12 bg-slate-800/40 border-b border-slate-800/60 flex justify-between items-center">
                 <span className="font-black text-white text-2xl tracking-tight">系統全域日誌記錄</span>
                 <button onClick={() => setLogs([])} className="text-xs text-slate-500 font-black uppercase tracking-widest hover:text-red-400 transition-colors">Clear Records</button>
              </div>
              <div className="divide-y divide-slate-800/40 max-h-[70vh] overflow-y-auto custom-scrollbar">
                {logs.length === 0 ? (
                  <div className="p-40 text-center text-slate-700 font-bold italic text-lg">SYSTEM IDLE: NO LOG DATA AVAILABLE</div>
                ) : logs.map(l => (
                  <div key={l.id} className="p-10 hover:bg-slate-800/20 transition-all flex gap-10 group">
                    <span className="text-[11px] font-mono text-slate-600 mt-2 font-bold tracking-tighter">{l.timestamp}</span>
                    <div className="flex-1">
                      <div className="flex items-center gap-4 mb-3">
                        <span className={`text-[10px] font-black px-4 py-1.5 rounded-full border ${l.level === 'error' ? 'bg-red-500/10 text-red-400 border-red-500/20 shadow-[0_0_10px_rgba(239,68,68,0.1)]' : 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20'}`}>
                          {l.level.toUpperCase()}
