import React, { useState, useEffect } from 'react';
import { 
  ChannelConfig, LogEntry, PipelineResult, TestResult 
} from './types';
import { MOCK_CHANNEL_STATE } from './constants';
import { ModuleCard } from './components/ModuleCard';

// 測試模組導入
import { runTrendExtractorTests } from './tests/TrendSignalExtractor.test';
import { runCandidateGeneratorTests } from './tests/CandidateThemeGenerator.test';
import { runPromptComposerTests } from './tests/PromptComposer.test';
import { runVideoGeneratorTests } from './tests/VideoGenerator.test';
import { runUploaderTests } from './tests/UploaderScheduler.test';

const App: React.FC = () => {
  const [channels, setChannels] = useState<ChannelConfig[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [activeChannelId, setByChannelId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'logs'>('dashboard');

  // Pipeline 狀態追蹤
  const [pipelineStates, setPipelineStates] = useState<Record<string, { currentStep: number; status: 'idle' | 'running' | 'success' | 'error'; data?: any }>>({});
  const [testResults, setTestResults] = useState<Record<string, TestResult | null>>({});

  // 表單狀態
  const [newChannelName, setNewChannelName] = useState("");
  const [newKeywords, setNewKeywords] = useState("AI, Technology, Future");

  useEffect(() => {
    const saved = localStorage.getItem('sas_channels_v2_6_stable');
    if (saved) {
      setChannels(JSON.parse(saved));
    } else {
      const demo: ChannelConfig = {
        id: 'demo-1',
        name: 'AI 探索實驗室 (預設)',
        regionCode: 'US',
        searchKeywords: ['AI', 'Tech'],
        channelState: MOCK_CHANNEL_STATE,
        schedule: { active: false, privacy_status: 'private' },
        auth: null,
        status: 'idle'
      };
      setChannels([demo]);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('sas_channels_v2_6_stable', JSON.stringify(channels));
  }, [channels]);

  const addLog = (channelId: string, level: 'info' | 'success' | 'error', msg: string) => {
    const entry: LogEntry = {
      id: Math.random().toString(),
      timestamp: new Date().toLocaleTimeString(),
      channelId,
      channelName: channels.find(c => c.id === channelId)?.name || 'System',
      level,
      message: msg
    };
    setLogs(prev => [entry, ...prev]);
  };

  const createChannel = () => {
    if (!newChannelName) return;
    const newChannel: ChannelConfig = {
      id: Date.now().toString(),
      name: newChannelName,
      regionCode: "US",
      searchKeywords: newKeywords.split(',').map(s => s.trim()),
      channelState: { ...MOCK_CHANNEL_STATE, niche: newKeywords },
      schedule: { active: false, privacy_status: 'private' },
      auth: null,
      status: 'idle'
    };
    setChannels([...channels, newChannel]);
    setIsAdding(false);
    setNewChannelName("");
    addLog(newChannel.id, 'success', `頻道「${newChannelName}」已加入監控。`);
  };

  const runPipeline = async (channel: ChannelConfig) => {
    setByChannelId(channel.id);
    setActiveTab('dashboard');
    addLog(channel.id, 'info', '初始化自動化流水線...');

    setPipelineStates(prev => ({ 
      ...prev, 
      [channel.id]: { currentStep: 1, status: 'running' } 
    }));

    try {
      const res = await fetch('/api/pipeline', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ channelConfig: channel })
      });

      if (!res.ok) throw new Error("API 離線");

      const result: PipelineResult = await res.json();
      if (result.success) {
        addLog(channel.id, 'success', '自動化流程成功完成。');
        setPipelineStates(prev => ({ 
          ...prev, 
          [channel.id]: { status: 'success', data: result, currentStep: 7 } 
        }));
      } else {
        throw new Error(result.error);
      }
    } catch (e: any) {
      addLog(channel.id, 'info', '偵測到環境限制，開啟視覺模擬展示...');
      simulatePipeline(channel.id);
    }
  };

  const simulatePipeline = async (channelId: string) => {
    const steps = [1, 2, 4, 5, 6];
    for (const step of steps) {
      setPipelineStates(prev => ({ 
        ...prev, 
        [channelId]: { currentStep: step, status: 'running' } 
      }));
      addLog(channelId, 'info', `正在執行模組：Step ${step}`);
      await new Promise(r => setTimeout(r, 1200));
    }

    addLog(channelId, 'success', '全模組展示完成。');
    setPipelineStates(prev => ({ 
      ...prev, 
      [channelId]: { 
        status: 'success', 
        currentStep: 7,
        data: {
          logs: ["趨勢分析完成 (100%)", "Veo 生成器：就緒"],
          videoUrl: "https://storage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4" 
        } 
      } 
    }));
  };

  const getModuleStatus = (channelId: string, step: number) => {
    const state = pipelineStates[channelId];
    if (!state) return 'idle';
    if (state.status === 'success' || state.currentStep > step) return 'success';
    if (state.currentStep === step && state.status === 'running') return 'loading';
    return 'idle';
  };

  // 重要修復：handleRunTest 必須回傳 Promise<TestResult> 以符合 ModuleCard 的 PropTypes
  const handleRunTest = async (moduleKey: string, testFn: () => Promise<TestResult>): Promise<TestResult> => {
    const res = await testFn();
    setTestResults(prev => ({ ...prev, [moduleKey]: res }));
    return res;
  };

  return (
    <div className="flex min-h-screen bg-[#020617] text-slate-200 antialiased font-sans">

      {/* 側邊導航 */}
      <aside className="w-80 bg-slate-900/40 border-r border-slate-800/60 flex flex-col fixed inset-y-0 z-50 backdrop-blur-3xl">
        <div className="p-10">
          <div className="flex items-center gap-4 mb-16">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-2xl shadow-indigo-500/20">S</div>
            <div>
              <h1 className="font-bold text-xl tracking-tight text-white leading-none">Shorts AI</h1>
              <p className="text-[10px] text-indigo-400 font-black uppercase tracking-widest mt-1">v2.6 Stable</p>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => { setActiveTab('dashboard'); setByChannelId(null); }}
              className={`w-full text-left px-6 py-4 rounded-2xl transition-all flex items-center gap-4 ${activeTab === 'dashboard' && !activeChannelId ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800/50'}`}
            >
