        <div className="p-10">
          <div className="flex items-center gap-4 mb-20 group">
            <div className="w-12 h-12 bg-indigo-600 rounded-[18px] flex items-center justify-center font-black text-white text-xl shadow-[0_0_25px_rgba(79,70,229,0.3)]">S</div>
            <div>
              <h1 className="font-black text-xl tracking-tight text-white leading-none">SHORTS AI</h1>
              <p className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.2em] mt-2">V2.8 PRO</p>
            </div>
          </div>

          <nav className="space-y-3">
            <button 
              onClick={() => { setActiveTab('dashboard'); setByChannelId(null); }}
              className={`w-full text-left px-6 py-4 rounded-2xl transition-all flex items-center gap-4 ${activeTab === 'dashboard' && !activeChannelId ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-400 hover:bg-slate-800/50'}`}
            >
              <span className="text-xl">📊</span> <span className="text-sm font-bold tracking-wide">核心控制台</span>
            </button>
            <button 
              onClick={() => setActiveTab('logs')}
              className={`w-full text-left px-6 py-4 rounded-2xl transition-all flex items-center gap-4 ${activeTab === 'logs' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-400 hover:bg-slate-800/50'}`}
            >
              <span className="text-xl">📜</span> <span className="text-sm font-bold tracking-wide">全域日誌</span>
            </button>
          </nav>

          <div className="mt-20">
            <div className="flex items-center justify-between mb-8 px-2">
               <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">頻道資源監控</p>
               <button onClick={() => setIsAdding(true)} className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all shadow-inner">+</button>
            </div>
            <div className="space-y-2">
              {channels.map(c => (
                <button 
                  key={c.id}
                  onClick={() => { setByChannelId(c.id); setActiveTab('dashboard'); }}
                  className={`w-full text-left px-5 py-4 rounded-xl text-xs font-bold transition-all truncate border ${activeChannelId === c.id ? 'bg-indigo-600/10 text-indigo-400 border-indigo-500/40' : 'text-slate-500 border-transparent hover:bg-slate-800/40'}`}
                >
                  {c.name}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-auto p-10 border-t border-slate-800/60">
           <div className="flex items-center gap-4">
              <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse"></div>
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">System Online</span>
           </div>
        </div>
