                  />

                  <ModuleCard 
                    title="Phase 02: 創意構思生成" stepNumber="02" description="Gemini 根據解析出的信號，優化出 3 組最具病毒式傳播力的影片主題。"
                    status={getModuleStatus(activeChannelId, 2)}
                    onRunTest={() => handleRunTest('cand', runCandidateGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.cand || null}
                  />

                  <ModuleCard 
                    title="Phase 05: Veo 3.1 影片生成" stepNumber="05" description="呼叫 Veo 核心模型生成 9:16 高解析度影片資產。"
                    status={getModuleStatus(activeChannelId, 5)}
                    onRunTest={() => handleRunTest('video', runVideoGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.video || null}
                  >
                    {pipelineStates[activeChannelId]?.data?.videoUrl && (
                      <div className="mt-12 rounded-[40px] overflow-hidden border-8 border-slate-900 bg-black aspect-[9/16] max-w-[320px] mx-auto shadow-2xl ring-1 ring-slate-800">
                         <video src={pipelineStates[activeChannelId].data.videoUrl} controls autoPlay loop className="w-full h-full object-cover" />
                      </div>
                    )}
                  </ModuleCard>

                  <ModuleCard 
                    title="Phase 06: 多頻道上傳排程" stepNumber="06" description="自動推送影片至 YouTube Studio 並自動配置標題與 SEO 標籤。"
                    status={getModuleStatus(activeChannelId, 6)}
                    onRunTest={() => handleRunTest('uploader', runUploaderTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.uploader || null}
                  />
               </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-slate-900/60 rounded-[48px] border border-slate-800/60 overflow-hidden shadow-3xl animate-fade-in backdrop-blur-xl">
              <div className="p-12 bg-slate-800/40 border-b border-slate-800 flex justify-between items-center">
                 <span className="font-black text-white text-2xl tracking-tight">核心系統全域日誌</span>
                 <button onClick={() => setLogs([])} className="text-xs text-slate-500 font-black uppercase hover:text-red-400">Clear Records</button>
              </div>
              <div className="divide-y divide-slate-800/40 max-h-[70vh] overflow-y-auto custom-scrollbar">
                {logs.length === 0 ? (
                  <div className="p-40 text-center text-slate-700 font-bold italic text-lg">SYSTEM READY: WAITING FOR ACTIVITY</div>
                ) : logs.map(l => (
                  <div key={l.id} className="p-10 hover:bg-slate-800/20 transition-all flex gap-10 group">
                    <span className="text-[11px] font-mono text-slate-600 mt-2 font-bold">{l.timestamp}</span>
                    <div className="flex-1">
                      <div className="flex items-center gap-4 mb-3">
                        <span className={`text-[10px] font-black px-4 py-1.5 rounded-full border ${l.level === 'error' ? 'bg-red-500/10 text-red-400 border-red-500/20' : 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20'}`}>
                          {l.level.toUpperCase()}
                        </span>
                        <span className="text-sm font-black text-slate-300 group-hover:text-indigo-400 transition-colors">{l.channelName}</span>
                      </div>
                      <p className="text-sm text-slate-500 leading-relaxed font-bold">{l.message}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  ChannelConfig, LogEntry, PipelineResult, TestResult 
} from './types';
import { MOCK_CHANNEL_STATE } from './constants';
import { ModuleCard } from './components/ModuleCard';

// 導入測試函數
import { runTrendExtractorTests } from './tests/TrendSignalExtractor.test';
import { runCandidateGeneratorTests } from './tests/CandidateThemeGenerator.test';
import { runVideoGeneratorTests } from './tests/VideoGenerator.test';
import { runUploaderTests } from './tests/UploaderScheduler.test';

const App: React.FC = () => {
  const [channels, setChannels] = useState<ChannelConfig[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [activeChannelId, setByChannelId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'logs'>('dashboard');

  const [pipelineStates, setPipelineStates] = useState<Record<string, { currentStep: number; status: 'idle'|'running'|'success'|'error'; data?: any }>>({});
  const [testResults, setTestResults] = useState<Record<string, TestResult | null>>({});

  const [newChannelName, setNewChannelName] = useState("");
  const [newKeywords, setNewKeywords] = useState("AI, Tech, Future");

  useEffect(() => {
    const saved = localStorage.getItem('sas_v2_9_stable');
    if (saved) {
      setChannels(JSON.parse(saved));
    } else {
      const demo: ChannelConfig = {
        id: 'demo-1',
        name: 'AI 科技研發部 (預設)',
        regionCode: 'US',
        searchKeywords: ['AI', 'Tech'],
        channelState: MOCK_CHANNEL_STATE,
        schedule: { active: false, privacy_status: 'private' },
        auth: null,
        status: 'idle'
      };
      setChannels([demo]);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('sas_v2_9_stable', JSON.stringify(channels));
  }, [channels]);

  const addLog = (channelId: string, level: 'info' | 'success' | 'error', msg: string) => {
    const entry: LogEntry = {
      id: Math.random().toString(),
      timestamp: new Date().toLocaleTimeString(),
      channelId,
      channelName: channels.find(c => c.id === channelId)?.name || 'System',
      level,
      message: msg
    };
    setLogs(prev => [entry, ...prev]);
  };

  const handleRunTest = async (moduleKey: string, testFn: () => Promise<TestResult>): Promise<TestResult> => {
    const res = await testFn();
    setTestResults(prev => ({ ...prev, [moduleKey]: res }));
    return res;
  };

  const runPipeline = async (channel: ChannelConfig) => {
    setByChannelId(channel.id);
    setActiveTab('dashboard');
    addLog(channel.id, 'info', '啟動全自動化指令集...');

    setPipelineStates(prev => ({ 
      ...prev, 
      [channel.id]: { currentStep: 1, status: 'running' } 
    }));

    try {
      const res = await fetch('/api/pipeline', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ channelConfig: channel })
      });

      if (!res.ok) throw new Error("Backend Connection Failed");

      const result: PipelineResult = await res.json();
      if (result.success) {
        addLog(channel.id, 'success', '自動化流水線執行完畢。');
        setPipelineStates(prev => ({ 
          ...prev, 
          [channel.id]: { status: 'success', data: result, currentStep: 7 } 
        }));
      } else {
        throw new Error(result.error);
      }
    } catch (e: any) {
      addLog(channel.id, 'info', '後端節點離線，切換至視覺模擬模式...');
      simulatePipeline(channel.id);
    }
  };

  const simulatePipeline = async (channelId: string) => {
    const steps = [1, 2, 5, 6];
    for (const step of steps) {
      setPipelineStates(prev => ({ ...prev, [channelId]: { currentStep: step, status: 'running' } }));
      await new Promise(r => setTimeout(r, 1200));
    }
    setPipelineStates(prev => ({ 
      ...prev, 
      [channelId]: { 
        status: 'success', 
        currentStep: 7,
        data: { videoUrl: "https://storage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4" } 
      } 
    }));
  };

  const getModuleStatus = (channelId: string, step: number) => {
    const state = pipelineStates[channelId];
    if (!state) return 'idle';
    if (state.status === 'success' || state.currentStep > step) return 'success';
    if (state.currentStep === step && state.status === 'running') return 'loading';
    return 'idle';
  };

  return (
    <div className="flex min-h-screen bg-[#020617] text-slate-200">

      {/* 側邊導航 */}
      <aside className="w-80 bg-slate-900/50 border-r border-slate-800/60 flex flex-col fixed inset-y-0 z-50 backdrop-blur-2xl">
        <div className="p-10">
          <div className="flex items-center gap-4 mb-16">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-white text-xl">S</div>
            <div>
              <h1 className="font-black text-xl tracking-tight text-white leading-none">SHORTS AI</h1>
              <p className="text-[10px] text-indigo-400 font-black uppercase tracking-widest mt-1">Command Center</p>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => { setActiveTab('dashboard'); setByChannelId(null); }}
              className={`w-full text-left px-6 py-4 rounded-xl transition-all flex items-center gap-4 ${activeTab === 'dashboard' && !activeChannelId ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-slate-400 hover:bg-slate-800/50'}`}
            >
              <span className="text-xl">📊</span> <span className="text-sm font-bold">控制台 Dashboard</span>
            </button>
            <button 
              onClick={() => setActiveTab('logs')}
              className={`w-full text-left px-6 py-4 rounded-xl transition-all flex items-center gap-4 ${activeTab === 'logs' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-slate-400 hover:bg-slate-800/50'}`}
            >
              <span className="text-xl">📜</span> <span className="text-sm font-bold">系統活動日誌</span>
            </button>
          </nav>

          <div className="mt-16">
            <div className="flex items-center justify-between mb-6 px-2">
               <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">活躍頻道節點</p>
               <button onClick={() => setIsAdding(true)} className="w-6 h-6 rounded-full bg-slate-800 flex items-center justify-center text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all">+</button>
            </div>
            <div className="space-y-1">
              {channels.map(c => (
                <button 
                  key={c.id}
                  onClick={() => { setByChannelId(c.id); setActiveTab('dashboard'); }}
                  className={`w-full text-left px-5 py-3 rounded-lg text-xs font-bold transition-all truncate border ${activeChannelId === c.id ? 'bg-indigo-600/10 text-indigo-400 border-indigo-500/30' : 'text-slate-500 border-transparent hover:bg-slate-800/30'}`}
                >
                  {c.name}
                </button>
              ))}
            </div>
          </div>
        </div>
      </aside>

      {/* 主介面區域 */}
      <main className="flex-1 ml-80 min-h-screen bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900/10 via-slate-950 to-slate-950">
        <header className="h-24 border-b border-slate-800/40 flex items-center justify-between px-12 bg-slate-950/70 backdrop-blur-xl sticky top-0 z-40">
          <div>
            <h2 className="font-black text-2xl text-white tracking-tight">
              {activeChannelId ? channels.find(c => c.id === activeChannelId)?.name : '系統概覽'}
            </h2>
            <p className="text-[10px] text-slate-500 mt-1 uppercase tracking-widest font-black opacity-60">Automation Command Interface</p>
          </div>
          <div className="w-12 h-12 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-indigo-400 text-xl">⚙️</div>
        </header>

        <div className="p-12 max-w-5xl mx-auto">
          {activeTab === 'dashboard' && !activeChannelId && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 animate-fade-in">
              {isAdding && (
                <div className="bg-slate-900 p-10 rounded-[2.5rem] border-2 border-indigo-500/50 shadow-2xl">
                  <h3 className="font-black text-white mb-8 tracking-tight">部署新自動化任務</h3>
                  <div className="space-y-6">
                    <input placeholder="頻道標示名稱" value={newChannelName} onChange={e => setNewChannelName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-sm font-bold focus:ring-1 focus:ring-indigo-500 outline-none" />
                    <input placeholder="核心分析關鍵字" value={newKeywords} onChange={e => setNewKeywords(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-sm font-bold focus:ring-1 focus:ring-indigo-500 outline-none" />
                    <button onClick={() => {
                        if (!newChannelName) return;
                        setChannels([...channels, {
                          id: Date.now().toString(),
                          name: newChannelName,
                          regionCode: "US",
                          searchKeywords: newKeywords.split(','),
                          channelState: MOCK_CHANNEL_STATE,
                          schedule: { active: false, privacy_status: 'private' },
                          auth: null,
                          status: 'idle'
                        }]);
                        setIsAdding(false);
                    }} className="w-full bg-indigo-600 py-5 rounded-xl text-sm font-black shadow-lg shadow-indigo-600/30 transition-all">部署自動化節點</button>
                    <button onClick={() => setIsAdding(false)} className="w-full text-slate-500 text-xs font-black uppercase py-2">取消部署</button>
                  </div>
                </div>
              )}

              {channels.map(c => (
                <div key={c.id} className="group bg-slate-900/50 p-10 rounded-[2.5rem] border border-slate-800 hover:border-indigo-500/50 transition-all shadow-xl">
                  <div className="w-16 h-16 bg-slate-950 rounded-2xl flex items-center justify-center text-3xl mb-8 group-hover:scale-110 transition-transform">📺</div>
                  <h3 className="font-black text-2xl text-white mb-3 tracking-tight">{c.name}</h3>
                  <p className="text-xs text-slate-500 font-bold mb-10">Tags: {c.searchKeywords.join(', ')}</p>
                  <button onClick={() => runPipeline(c)} className="w-full py-5 bg-slate-800 group-hover:bg-indigo-600 rounded-2xl text-sm font-black transition-all active:scale-95 shadow-lg">🚀 啟動任務</button>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'dashboard' && activeChannelId && (
            <div className="animate-fade-in space-y-10 pb-20">
               <div className="bg-slate-900/60 p-12 rounded-[3rem] border border-slate-800 shadow-2xl flex items-center justify-between">
                  <div className="flex items-center gap-8">
                    <div className="w-20 h-20 bg-indigo-600/10 rounded-[2rem] flex items-center justify-center text-4xl border border-indigo-500/20">⚡</div>
                    <div>
                      <h3 className="font-black text-3xl text-white mb-2">{channels.find(c => c.id === activeChannelId)?.name}</h3>
                      <p className="text-xs text-slate-500 font-bold uppercase tracking-widest flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
                        Pipeline Monitoring: {pipelineStates[activeChannelId]?.status === 'success' ? 'Finished' : 'Running'}
                      </p>
                    </div>
                  </div>
                  <button onClick={() => runPipeline(channels.find(c => c.id === activeChannelId)!)} className="px-10 py-5 bg-indigo-600 hover:bg-indigo-500 rounded-2xl text-sm font-black shadow-xl transition-all">重新啟動流程</button>
               </div>

               <div className="space-y-8 max-w-4xl mx-auto">
                  <ModuleCard 
                    title="Phase 01: 趨勢信號提取" stepNumber="01" description="解析 YouTube 市場動向，計算標籤與主體頻率。"
                    status={getModuleStatus(activeChannelId, 1) as any}
                    onRunTest={() => handleRunTest('trend', runTrendExtractorTests)}
                    onExecute={() => {}} canExecute={true} data={pipelineStates[activeChannelId]?.data?.logs} 
                    testResult={testResults.trend || null}
                  />

                  <ModuleCard 
                    title="Phase 02: 候選題材生成" stepNumber="02" description="Gemini 根據解析信號生成具病毒式潛力的影片構思。"
                    status={getModuleStatus(activeChannelId, 2) as any}
                    onRunTest={() => handleRunTest('cand', runCandidateGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.cand || null}
                  />

                  <ModuleCard 
                    title="Phase 05: Veo 3.1 影片生成" stepNumber="05" description="呼叫 Google Veo 核心模型生成高畫質短影片。"
                    status={getModuleStatus(activeChannelId, 5) as any}
                    onRunTest={() => handleRunTest('video', runVideoGeneratorTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.video || null}
                  >
                    {pipelineStates[activeChannelId]?.data?.videoUrl && (
                      <div className="mt-10 rounded-[2.5rem] overflow-hidden border-8 border-slate-900 bg-black aspect-[9/16] max-w-[300px] mx-auto shadow-2xl">
                         <video src={pipelineStates[activeChannelId].data.videoUrl} controls autoPlay loop className="w-full h-full object-cover" />
                      </div>
                    )}
                  </ModuleCard>

                  <ModuleCard 
                    title="Phase 06: 上傳與排程發佈" stepNumber="06" description="自動推送至 YouTube Studio 並自動配置標題與 SEO。"
                    status={getModuleStatus(activeChannelId, 6) as any}
                    onRunTest={() => handleRunTest('uploader', runUploaderTests)}
                    onExecute={() => {}} canExecute={true} data={null} 
                    testResult={testResults.uploader || null}
                  />
               </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-slate-900 rounded-[3rem] border border-slate-800 overflow-hidden shadow-2xl animate-fade-in">
              <div className="p-8 bg-slate-800/40 border-b border-slate-800 flex justify-between items-center">
                 <span className="font-black text-white text-lg">全域活動日誌</span>
                 <button onClick={() => setLogs([])} className="text-xs text-slate-500 font-black uppercase hover:text-red-400">清除記錄</button>
              </div>
              <div className="divide-y divide-slate-800/30 max-h-[70vh] overflow-y-auto custom-scrollbar">
                {logs.length === 0 ? (
                  <div className="p-32 text-center text-slate-700 font-bold italic">Waiting for activity...</div>
                ) : logs.map(l => (
                  <div key={l.id} className="p-8 hover:bg-slate-800/20 transition-all flex gap-8 group">
                    <span className="text-[10px] font-mono text-slate-600 mt-1.5">{l.timestamp}</span>
                    <div className="flex-1">
                      <div className="flex items-center gap-3 mb-2">
                        <span className={`text-[9px] font-black px-3 py-1 rounded-full ${l.level === 'error' ? 'bg-red-500/10 text-red-400 border-red-500/20' : 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20'}`}>
                          {l.level.toUpperCase()}
                        </span>
                        <span className="text-sm font-bold text-slate-300 group-hover:text-indigo-400 transition-colors">{l.channelName}</span>
                      </div>
                      <p className="text-sm text-slate-500 font-medium leading-relaxed">{l.message}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;
